head.b:skin:
/* ============================================================
   INRY-BIBLIO — DESIGN TOKENS
   Direction: "Dossier scolaire" — cahier, tampon administratif,
   papier kraft, vert/or sobre. Pas de bleu corporate edtech.
   ============================================================ */

:root {
  /* --- Palette --- */
  --paper: #f3ead8;          /* fond papier kraft clair */
  --paper-dark: #e8dcc2;
  --ink: #2a2620;            /* texte principal, encre noire/brune */
  --ink-soft: #5c5446;
  --kraft: #c9a96b;          /* bordures, lignes de cahier */
  --kraft-line: #d8c49a;
  --green: #1f6f50;          /* vert "tampon officiel" */
  --green-dark: #154d38;
  --gold: #b8862f;           /* or / sceau */
  --gold-light: #d9ab52;
  --red-stamp: #9c3b2e;      /* rouge tampon */
  --cream-card: #fbf6ea;
  --surface: #ffffff;
  --shadow-color: rgba(42, 38, 32, 0.18);

  /* --- Type scale --- */
  --font-display: 'Fraunces', 'Amiri', serif;
  --font-body: 'Source Sans 3', 'Noto Sans Arabic', sans-serif;
  --font-mono: 'JetBrains Mono', monospace;

  --fs-xs: 0.75rem;
  --fs-sm: 0.875rem;
  --fs-base: 1rem;
  --fs-md: 1.125rem;
  --fs-lg: 1.375rem;
  --fs-xl: 1.875rem;
  --fs-2xl: 2.5rem;
  --fs-3xl: 3.5rem;

  /* --- Spacing --- */
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.5rem;
  --space-6: 2rem;
  --space-8: 3rem;
  --space-10: 4rem;
  --space-12: 6rem;

  /* --- Misc --- */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 14px;
  --border-w: 1.5px;
  --transition: 180ms cubic-bezier(0.4, 0, 0.2, 1);
  --max-width: 1240px;
}

[data-theme="dark"] {
  --paper: #1b1812;
  --paper-dark: #15120e;
  --ink: #ede4d2;
  --ink-soft: #b8ab8f;
  --kraft: #4a3f2a;
  --kraft-line: #382f20;
  --green: #4caf83;
  --green-dark: #2e7a58;
  --gold: #d9ab52;
  --gold-light: #e8c785;
  --red-stamp: #c25646;
  --cream-card: #241f17;
  --surface: #211c14;
  --shadow-color: rgba(0, 0, 0, 0.45);
}

/* ============================================================
   RESET
   ============================================================ */
*, *::before, *::after { box-sizing: border-box; }
html, body { margin: 0; padding: 0; }
img, svg { display: block; max-width: 100%; }
a { color: inherit; text-decoration: none; }
button { font-family: inherit; cursor: pointer; }
ul, ol { margin: 0; padding: 0; list-style: none; }
h1, h2, h3, h4, p { margin: 0; }
input, select, textarea, button { font-size: inherit; }

html {
  scroll-behavior: smooth;
}

@media (prefers-reduced-motion: reduce) {
  html { scroll-behavior: auto; }
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

body {
  background: var(--paper);
  color: var(--ink);
  font-family: var(--font-body);
  font-size: var(--fs-base);
  line-height: 1.55;
  transition: background var(--transition), color var(--transition);
  background-image:
    radial-gradient(ellipse at top left, rgba(184, 134, 47, 0.05), transparent 50%),
    radial-gradient(ellipse at bottom right, rgba(31, 111, 80, 0.05), transparent 50%);
}

/* RTL handling */
html[dir="rtl"] body { font-family: 'Noto Sans Arabic', 'Source Sans 3', sans-serif; }
html[dir="rtl"] .ltr-only { direction: ltr; unicode-bidi: isolate; }

:focus-visible {
  outline: 2.5px solid var(--gold);
  outline-offset: 2px;
  border-radius: 2px;
}

/* ============================================================
   PAPER TEXTURE / NOTEBOOK LINES (signature element)
   ============================================================ */
.paper-texture {
  background-image:
    repeating-linear-gradient(
      transparent, transparent 27px,
      var(--kraft-line) 27px, var(--kraft-line) 28px
    );
  background-position: 0 6px;
}

.stamp {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  border: 2px solid var(--green);
  color: var(--green);
  border-radius: 50px;
  padding: var(--space-1) var(--space-4);
  font-family: var(--font-display);
  font-weight: 600;
  font-size: var(--fs-sm);
  letter-spacing: 0.04em;
  transform: rotate(-2deg);
  background: transparent;
}

[data-theme="dark"] .stamp { color: var(--green); border-color: var(--green); }

/* ============================================================
   TYPOGRAPHY
   ============================================================ */
.font-display {
  font-family: var(--font-display);
}

h1, h2, h3, .heading {
  font-family: var(--font-display);
  font-weight: 600;
  color: var(--ink);
  letter-spacing: -0.01em;
}

html[dir="rtl"] h1, html[dir="rtl"] h2, html[dir="rtl"] h3, html[dir="rtl"] .heading {
  font-family: 'Amiri', 'Noto Sans Arabic', serif;
  letter-spacing: 0;
}

.eyebrow {
  font-size: var(--fs-xs);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--gold);
  font-weight: 700;
}
html[dir="rtl"] .eyebrow { text-transform: none; letter-spacing: 0.02em; }

/* ============================================================
   LAYOUT
   ============================================================ */
.container {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0 var(--space-5);
}

.skip-link {
  position: absolute;
  left: -999px;
  top: 0;
  background: var(--green);
  color: #fff;
  padding: var(--space-2) var(--space-4);
  z-index: 200;
}
.skip-link:focus { left: var(--space-3); top: var(--space-3); }

/* ============================================================
   HEADER
   ============================================================ */
.site-header {
  position: sticky;
  top: 0;
  z-index: 100;
  background: var(--paper);
  border-bottom: var(--border-w) solid var(--kraft);
  backdrop-filter: blur(6px);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-5);
  padding: var(--space-3) 0;
}

.brand {
  display: flex;
  align-items: center;
  gap: var(--space-3);
}

.brand-seal {
  width: 42px;
  height: 42px;
  flex-shrink: 0;
}

.brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.brand-name {
  font-family: var(--font-display);
  font-size: var(--fs-lg);
  font-weight: 700;
  color: var(--ink);
}

.brand-tagline {
  font-size: var(--fs-xs);
  color: var(--ink-soft);
}

.main-nav {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.nav-link {
  position: relative;
  padding: var(--space-2) var(--space-3);
  font-weight: 600;
  font-size: var(--fs-sm);
  color: var(--ink-soft);
  border-radius: var(--radius-sm);
  transition: color var(--transition), background var(--transition);
  white-space: nowrap;
}

.nav-link:hover { color: var(--green); background: rgba(31, 111, 80, 0.08); }
.nav-link.active { color: var(--green); }
.nav-link.active::after {
  content: "";
  position: absolute;
  left: var(--space-3);
  right: var(--space-3);
  bottom: -1px;
  height: 2px;
  background: var(--green);
  border-radius: 2px;
}

.header-controls {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.icon-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border-radius: var(--radius-md);
  border: var(--border-w) solid var(--kraft);
  background: var(--surface);
  color: var(--ink);
  transition: border-color var(--transition), transform var(--transition);
}
.icon-btn:hover { border-color: var(--green); transform: translateY(-1px); }
.icon-btn svg { width: 18px; height: 18px; }

.lang-switch {
  display: flex;
  border: var(--border-w) solid var(--kraft);
  border-radius: var(--radius-md);
  overflow: hidden;
}
.lang-btn {
  padding: var(--space-2) var(--space-3);
  background: var(--surface);
  color: var(--ink-soft);
  font-weight: 700;
  font-size: var(--fs-xs);
  border: none;
  transition: background var(--transition), color var(--transition);
}
.lang-btn.active { background: var(--green); color: #fff; }
.lang-btn:not(.active):hover { background: var(--paper-dark); }

.mobile-nav-toggle { display: none; }

@media (max-width: 900px) {
  .main-nav { display: none; }
  .mobile-nav-toggle { display: inline-flex; }
}
/* ============================================================
   HERO
   ============================================================ */
.hero {
  position: relative;
  padding: var(--space-10) 0 var(--space-8);
  overflow: hidden;
}

.hero-inner {
  display: grid;
  grid-template-columns: 1.1fr 0.9fr;
  gap: var(--space-8);
  align-items: center;
}

@media (max-width: 900px) {
  .hero-inner { grid-template-columns: 1fr; }
}

.hero-eyebrow-row {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  margin-bottom: var(--space-4);
}

.hero h1 {
  font-size: clamp(2rem, 4.2vw, var(--fs-3xl));
  line-height: 1.08;
  margin-bottom: var(--space-4);
}

.hero-subtitle {
  font-size: var(--fs-md);
  color: var(--ink-soft);
  max-width: 540px;
  margin-bottom: var(--space-6);
}

.search-bar {
  display: flex;
  gap: var(--space-2);
  max-width: 520px;
}

.search-bar input {
  flex: 1;
  padding: var(--space-3) var(--space-4);
  border: 2px solid var(--kraft);
  border-radius: var(--radius-md);
  background: var(--surface);
  color: var(--ink);
  font-size: var(--fs-base);
  transition: border-color var(--transition);
}
.search-bar input:focus { border-color: var(--green); }

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-5);
  border-radius: var(--radius-md);
  border: 2px solid transparent;
  font-weight: 700;
  font-size: var(--fs-sm);
  transition: transform var(--transition), box-shadow var(--transition), background var(--transition);
  white-space: nowrap;
}
.btn-primary {
  background: var(--green);
  color: #fff;
}
.btn-primary:hover { background: var(--green-dark); transform: translateY(-1px); box-shadow: 0 4px 14px rgba(31,111,80,0.3); }

.btn-secondary {
  background: transparent;
  border-color: var(--kraft);
  color: var(--ink);
}
.btn-secondary:hover { border-color: var(--gold); color: var(--gold); }

.btn-ghost {
  background: transparent;
  color: var(--ink-soft);
}
.btn-ghost:hover { color: var(--green); }

.hero-stats {
  display: flex;
  gap: var(--space-6);
  margin-top: var(--space-6);
}
.hero-stat-num {
  font-family: var(--font-display);
  font-size: var(--fs-2xl);
  color: var(--green);
  font-weight: 700;
}
.hero-stat-label {
  font-size: var(--fs-xs);
  color: var(--ink-soft);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

/* The "dossier" signature visual */
.hero-visual {
  position: relative;
  display: flex;
  justify-content: center;
}

.dossier-stack {
  position: relative;
  width: 320px;
  height: 380px;
}

.dossier-card {
  position: absolute;
  width: 280px;
  height: 360px;
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft);
  border-radius: var(--radius-md);
  box-shadow: 0 18px 40px var(--shadow-color);
  padding: var(--space-5);
}
.dossier-card.back-1 { transform: rotate(-7deg) translate(-18px, 10px); opacity: 0.85; }
.dossier-card.back-2 { transform: rotate(6deg) translate(20px, 18px); opacity: 0.7; }
.dossier-card.front {
  z-index: 2;
  background: var(--surface);
}

.dossier-line {
  height: 9px;
  background: var(--kraft-line);
  border-radius: 2px;
  margin-bottom: var(--space-3);
}
.dossier-line.short { width: 60%; }
.dossier-line.tiny { width: 35%; height: 7px; }

.dossier-stamp-seal {
  position: absolute;
  bottom: var(--space-5);
  right: var(--space-5);
  width: 76px;
  height: 76px;
  transform: rotate(-12deg);
}
html[dir="rtl"] .dossier-stamp-seal { right: auto; left: var(--space-5); transform: rotate(12deg); }

/* ============================================================
   SECTION HEADERS
   ============================================================ */
.section {
  padding: var(--space-10) 0;
}
.section-header {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: var(--space-4);
  margin-bottom: var(--space-6);
  flex-wrap: wrap;
}
.section-header h2 {
  font-size: var(--fs-2xl);
}

/* ============================================================
   SUBJECT / LEVEL QUICK GRID (home)
   ============================================================ */
.quick-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: var(--space-4);
}

.quick-tile {
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
  padding: var(--space-5);
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft);
  border-radius: var(--radius-lg);
  transition: transform var(--transition), border-color var(--transition), box-shadow var(--transition);
}
.quick-tile:hover {
  transform: translateY(-3px);
  border-color: var(--green);
  box-shadow: 0 10px 24px var(--shadow-color);
}
.quick-tile-icon {
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-md);
  background: rgba(31, 111, 80, 0.1);
  color: var(--green);
}
.quick-tile-icon svg { width: 22px; height: 22px; }
.quick-tile-name { font-weight: 700; font-family: var(--font-display); font-size: var(--fs-md); }
.quick-tile-count { font-size: var(--fs-xs); color: var(--ink-soft); }
.level-category {
  grid-column: 1 / -1;
  display: block;
}
.level-category .quick-tile {
  flex-direction: row;
  align-items: center;
  gap: var(--space-4);
  cursor: pointer;
  position: relative;
}
.expand-icon {
  margin-left: auto;
  color: var(--ink-soft);
  transition: transform var(--transition);
}
.level-category .quick-tile.expanded .expand-icon { transform: rotate(180deg); }
.level-subgrid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: var(--space-4);
  margin-top: var(--space-3);
}
.sub-tile { background: var(--bg-subtle); border-color: var(--border-subtle); }
.sub-tile:hover { border-color: var(--green); }
.level-subgrid .quick-tile {
  flex-direction: column;
  align-items: stretch;
  gap: var(--space-3);
}

/* ============================================================
   FILTER BAR (library page)
   ============================================================ */
.filters-bar {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
  align-items: center;
  padding: var(--space-4);
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft);
  border-radius: var(--radius-lg);
  margin-bottom: var(--space-6);
}

.filter-select {
  padding: var(--space-2) var(--space-3);
  border: 2px solid var(--kraft);
  border-radius: var(--radius-sm);
  background: var(--surface);
  color: var(--ink);
  font-weight: 600;
  font-size: var(--fs-sm);
  min-width: 140px;
  transition: border-color var(--transition);
}
.filter-select:focus { border-color: var(--green); }

.filters-meta {
  margin-left: auto;
  font-size: var(--fs-sm);
  color: var(--ink-soft);
  font-weight: 600;
}
html[dir="rtl"] .filters-meta { margin-left: 0; margin-right: auto; }

/* ============================================================
   DOCUMENT GRID + CARD
   ============================================================ */
.doc-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(290px, 1fr));
  gap: var(--space-5);
}

.doc-card {
  display: flex;
  flex-direction: column;
  background: var(--surface);
  border: var(--border-w) solid var(--kraft);
  border-radius: var(--radius-lg);
  overflow: hidden;
  transition: transform var(--transition), box-shadow var(--transition);
  position: relative;
}
.doc-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 14px 30px var(--shadow-color);
}

.doc-card-head {
  padding: var(--space-4) var(--space-4) 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-2);
}

.doc-badge {
  font-size: var(--fs-xs);
  font-weight: 700;
  padding: 2px var(--space-2);
  border-radius: 50px;
  white-space: nowrap;
}
.doc-badge.type-bac-bem { background: rgba(156, 59, 46, 0.12); color: var(--red-stamp); }
.doc-badge.type-cours { background: rgba(31, 111, 80, 0.12); color: var(--green); }
.doc-badge.type-corriges { background: rgba(184, 134, 47, 0.15); color: var(--gold); }
.doc-badge.type-exercices { background: rgba(90, 60, 138, 0.12); color: #5a3c8a; }
.doc-badge.type-devoir { background: rgba(44, 91, 138, 0.12); color: #2c5b8a; }
.doc-badge.type-composition { background: rgba(156, 59, 46, 0.12); color: var(--red-stamp); }
.doc-badge.type-examens { background: rgba(156, 59, 46, 0.12); color: var(--red-stamp); }
.doc-badge.type-resumes { background: rgba(47, 122, 58, 0.12); color: #2f7a3a; }

.doc-year {
  font-size: var(--fs-xs);
  color: var(--ink-soft);
  font-family: var(--font-mono);
}

.doc-card-body {
  padding: var(--space-3) var(--space-4);
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.doc-title {
  font-family: var(--font-display);
  font-size: var(--fs-md);
  font-weight: 600;
  line-height: 1.3;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.doc-meta-row {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2);
  font-size: var(--fs-xs);
  color: var(--ink-soft);
}
.doc-meta-row span { display: inline-flex; align-items: center; gap: 4px; }
.doc-meta-row svg { width: 13px; height: 13px; }

.doc-card-foot {
  display: flex;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-4);
  border-top: 1px solid var(--kraft-line);
}
.doc-card-foot .btn { flex: 1; padding: var(--space-2) var(--space-3); font-size: var(--fs-xs); }

.host-tag {
  position: absolute;
  top: var(--space-3);
  inset-inline-end: var(--space-3);
  font-size: 10px;
  font-weight: 800;
  text-transform: uppercase;
  padding: 2px 8px;
  border-radius: 50px;
  background: var(--ink);
  color: var(--paper);
  letter-spacing: 0.05em;
}

/* ============================================================
   EMPTY STATE
   ============================================================ */
.empty-state {
  text-align: center;
  padding: var(--space-10) var(--space-4);
  color: var(--ink-soft);
}
.empty-state svg { width: 64px; height: 64px; margin: 0 auto var(--space-4); opacity: 0.4; }
.empty-state h3 { font-size: var(--fs-lg); color: var(--ink); margin-bottom: var(--space-2); }

/* ============================================================
   MODAL (preview + download)
   ============================================================ */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(20, 18, 14, 0.65);
  display: none;
  align-items: center;
  justify-content: center;
  padding: var(--space-2);
  z-index: 1000;
  backdrop-filter: blur(3px);
}
.modal-overlay.open { display: flex; }

.modal-box {
  background: var(--surface);
  border-radius: var(--radius-lg);
  width: min(98vw, 1600px);
  height: min(96vh, 900px);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border: var(--border-w) solid var(--kraft);
  box-shadow: 0 30px 60px rgba(0,0,0,0.35);
}

.modal-head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-3);
  padding: var(--space-5);
  border-bottom: var(--border-w) solid var(--kraft-line);
}
.modal-head h3 { font-size: var(--fs-lg); line-height: 1.3; }

.modal-body {
  display: flex;
  flex-direction: row;
  overflow: hidden;
  flex: 1;
  min-height: 0;
}
.modal-preview { flex: 0 0 50%; min-width: 200px; }
.modal-info { flex: 1 1 50%; min-width: 200px; }
.modal-resize-handle {
  flex: 0 0 5px;
  cursor: col-resize;
  background: var(--kraft-line);
  position: relative;
  z-index: 2;
  transition: background 0.15s;
}
.modal-resize-handle:hover,
.modal-resize-handle.active { background: var(--green); }

@media (max-width: 900px) {
  .modal-body { flex-direction: column; }
  .modal-preview { flex: 0 0 50vh !important; }
  .modal-info { flex: 1 1 auto !important; }
  .modal-resize-handle { display: none; }
}

.modal-preview {
  background: var(--paper-dark);
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 0;
  overflow: hidden;
}
.modal-preview iframe {
  width: 100%;
  height: 100%;
  min-height: 0;
  border: none;
}

.preview-fallback {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  padding: var(--space-4);
  text-align: center;
  color: var(--ink-soft);
}

.modal-info {
  padding: var(--space-4);
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
  overflow: hidden;
  min-height: 0;
}
.modal-info p { color: var(--ink-soft); font-size: var(--fs-sm); }

.modal-detail-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-3);
  font-size: var(--fs-sm);
}
.modal-detail-grid dt { color: var(--ink-soft); font-size: var(--fs-xs); text-transform: uppercase; letter-spacing: 0.04em; }
.modal-detail-grid dd { font-weight: 700; margin: 0; }

.modal-actions {
  margin-top: auto;
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.modal-close {
  width: 34px;
  height: 34px;
  border-radius: 50%;
  border: var(--border-w) solid var(--kraft);
  background: var(--surface);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.modal-close:hover { border-color: var(--red-stamp); color: var(--red-stamp); }

.modal-ai-chat {
  border-top: var(--border-w) solid var(--kraft-line);
  padding-top: var(--space-2);
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  flex: 1;
  min-height: 0;
  overflow: hidden;
}
.modal-ai-messages {
  flex: 1;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  padding: var(--space-2) 0;
  min-height: 0;
}
.modal-ai-messages .chat-msg {
  max-width: 80%;
}
/* Force same bot base styles as main assistant page */
.modal-ai-messages .chat-msg.bot {
  white-space: normal;
}
.modal-ai-messages .chat-msg.bot img {
  max-width: 100%;
  border-radius: var(--radius-md);
  margin-top: var(--space-1);
}
.modal-ai-input-row {
  display: flex;
  gap: var(--space-1);
  align-items: flex-end;
  flex-shrink: 0;
}
.modal-ai-input-row textarea {
  flex: 1;
  resize: none;
  padding: var(--space-2) var(--space-3);
  border: 2px solid var(--kraft);
  border-radius: var(--radius-md);
  background: var(--surface);
  color: var(--ink);
  font-family: inherit;
  font-size: var(--fs-xs);
  min-height: 32px;
  max-height: 80px;
  box-sizing: border-box;
}
.modal-ai-input-row textarea:focus { border-color: var(--green); }
.modal-ai-input-row .btn { padding: var(--space-2) var(--space-3); flex-shrink: 0; }
.modal-ai-tools {
  display: flex;
  gap: var(--space-1);
  flex-shrink: 0;
}
.modal-ai-tools .btn {
  font-size: var(--fs-xs);
  padding: var(--space-1) var(--space-2);
}
.modal-ai-file-tag { margin: 0; flex-shrink: 0; }

.modal-ai-suggestions {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1);
}
.modal-ai-suggestions .chip {
  font-size: 11px;
  padding: 4px 10px;
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft-line);
  border-radius: 50px;
  cursor: pointer;
  transition: border-color var(--transition);
}
.modal-ai-suggestions .chip:hover { border-color: var(--green); }

/* Fullscreen chat mode — hides everything except the chat */
.modal-box.chat-full .modal-preview { display: none; }
.modal-box.chat-full .modal-info { flex: 1 1 100% !important; }
.modal-box.chat-full .modal-body > .modal-resize-handle { display: none; }
.modal-box.chat-full .modal-info > div:not(.modal-ai-chat),
.modal-box.chat-full .eyebrow,
.modal-box.chat-full #modal-description,
.modal-box.chat-full .modal-detail-grid,
.modal-box.chat-full .modal-actions { display: none; }
.modal-box.chat-full .modal-info { padding: 0; overflow: hidden; }
.modal-box.chat-full .modal-ai-chat { border-top: none; padding: var(--space-4); flex: 1; }
.modal-box.chat-full .modal-ai-messages { flex: 1; min-height: 200px; }

/* ============================================================
   MOBILE NAV DRAWER
   ============================================================ */
.mobile-drawer {
  position: fixed;
  inset: 0;
  z-index: 150;
  display: none;
}
.mobile-drawer.open { display: block; }
.mobile-drawer-backdrop {
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0.5);
}
.mobile-drawer-panel {
  position: absolute;
  top: 0;
  inset-inline-end: 0;
  width: min(300px, 85vw);
  height: 100%;
  background: var(--paper);
  padding: var(--space-5);
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  border-inline-start: var(--border-w) solid var(--kraft);
}
.mobile-drawer .nav-link { padding: var(--space-3); font-size: var(--fs-md); }

/* ============================================================
   FOOTER
   ============================================================ */
.site-footer {
  border-top: var(--border-w) solid var(--kraft);
  padding: var(--space-8) 0 var(--space-6);
  margin-top: var(--space-10);
}
.footer-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-4);
}
.footer-about { max-width: 480px; color: var(--ink-soft); font-size: var(--fs-sm); }
.footer-meta { font-size: var(--fs-xs); color: var(--ink-soft); text-align: end; }

/* ============================================================
   TOAST
   ============================================================ */
.toast {
  position: fixed;
  bottom: var(--space-5);
  inset-inline-start: 50%;
  transform: translateX(-50%) translateY(20px);
  background: var(--ink);
  color: var(--paper);
  padding: var(--space-3) var(--space-5);
  border-radius: 50px;
  font-size: var(--fs-sm);
  font-weight: 600;
  z-index: 2000;
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--transition), transform var(--transition);
}
html[dir="rtl"] .toast { transform: translateX(50%) translateY(20px); }
.toast.show { opacity: 1; transform: translateX(-50%) translateY(0); pointer-events: auto; }
html[dir="rtl"] .toast.show { transform: translateX(50%) translateY(0); }

/* ============================================================
   PAGE LOAD ANIMATION (orchestrated, restrained)
   ============================================================ */
@keyframes riseIn {
  from { opacity: 0; transform: translateY(14px); }
  to { opacity: 1; transform: translateY(0); }
}
.animate-in { animation: riseIn 0.5s cubic-bezier(0.4,0,0.2,1) both; }
.delay-1 { animation-delay: 0.06s; }
.delay-2 { animation-delay: 0.12s; }
.delay-3 { animation-delay: 0.18s; }

/* ============================================================
   UTILITIES
   ============================================================ */
.hidden { display: none !important; }
.text-center { text-align: center; }
.flex-center { display: flex; align-items: center; justify-content: center; }
.visually-hidden {
  position: absolute;
  width: 1px; height: 1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
}
/* ============================================================
   ASSISTANT PAGE (chat)
   ============================================================ */
.assistant-page {
  max-width: 880px;
  margin: 0 auto;
  padding: var(--space-6) var(--space-5) var(--space-10);
  display: flex;
  flex-direction: column;
  height: calc(100vh - 70px);
}

.assistant-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
  padding-bottom: var(--space-4);
  border-bottom: var(--border-w) solid var(--kraft-line);
  margin-bottom: var(--space-4);
}

.assistant-header-text h2 { font-size: var(--fs-xl); }
.assistant-header-text p { color: var(--ink-soft); font-size: var(--fs-sm); margin-top: 4px; }

.provider-pill {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  font-size: var(--fs-xs);
  font-weight: 700;
  padding: var(--space-2) var(--space-3);
  border-radius: 50px;
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft);
  color: var(--ink-soft);
  white-space: nowrap;
}
.provider-pill .dot { width: 8px; height: 8px; border-radius: 50%; background: var(--green); flex-shrink: 0; }
.provider-pill.off .dot { background: var(--red-stamp); }

.chat-scroll {
  flex: 1;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  padding: var(--space-2) var(--space-1) var(--space-4);
}

.chat-msg {
  max-width: 80%;
  padding: var(--space-3) var(--space-4);
  border-radius: var(--radius-lg);
  font-size: var(--fs-sm);
  line-height: 1.55;
  white-space: pre-wrap;
}
.chat-msg.user {
  align-self: flex-end;
  background: var(--green);
  color: #fff;
  border-bottom-right-radius: 4px;
}
html[dir="rtl"] .chat-msg.user { align-self: flex-start; border-bottom-right-radius: var(--radius-lg); border-bottom-left-radius: 4px; }

.chat-msg.bot {
  align-self: flex-start;
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft-line);
  color: var(--ink);
  border-bottom-left-radius: 4px;
  white-space: normal;
}
html[dir="rtl"] .chat-msg.bot { align-self: flex-end; border-bottom-left-radius: var(--radius-lg); border-bottom-right-radius: 4px; }

.chat-msg.system-note {
  align-self: center;
  background: transparent;
  border: 1.5px dashed var(--kraft);
  color: var(--ink-soft);
  font-size: var(--fs-xs);
  text-align: center;
}

.chat-empty {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  color: var(--ink-soft);
  gap: var(--space-3);
  padding: var(--space-6);
}
.chat-empty svg { width: 56px; height: 56px; opacity: 0.4; }

.suggestion-chips {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2);
  justify-content: center;
  margin-top: var(--space-3);
}
.chip {
  padding: var(--space-2) var(--space-3);
  border-radius: 50px;
  border: var(--border-w) solid var(--kraft);
  background: var(--surface);
  font-size: var(--fs-xs);
  font-weight: 600;
  color: var(--ink);
  transition: border-color var(--transition), color var(--transition);
}
.chip:hover { border-color: var(--green); color: var(--green); }

.typing-dots {
  display: inline-flex;
  gap: 4px;
  align-items: center;
  padding: var(--space-1) 0;
}
.typing-dots span {
  width: 6px; height: 6px;
  border-radius: 50%;
  background: var(--ink-soft);
  animation: typingPulse 1.2s infinite ease-in-out;
}
.typing-dots span:nth-child(2) { animation-delay: 0.15s; }
.typing-dots span:nth-child(3) { animation-delay: 0.3s; }
@keyframes typingPulse {
  0%, 60%, 100% { opacity: 0.3; transform: translateY(0); }
  30% { opacity: 1; transform: translateY(-3px); }
}

.chat-input-row {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  padding-top: var(--space-4);
  border-top: var(--border-w) solid var(--kraft-line);
}
.chat-input-main {
  display: flex;
  gap: var(--space-2);
  align-items: flex-end;
}
.chat-input-main textarea {
  flex: 1;
  resize: none;
  padding: var(--space-3) var(--space-4);
  border: 2px solid var(--kraft);
  border-radius: var(--radius-md);
  background: var(--surface);
  color: var(--ink);
  font-family: inherit;
  font-size: var(--fs-base);
  min-height: 52px;
  max-height: 140px;
  transition: border-color var(--transition);
}
.chat-input-main textarea:focus { border-color: var(--green); }
.chat-input-main .btn-primary { align-self: flex-end; }

.chat-input-tools {
  display: flex;
  gap: var(--space-1);
  justify-content: flex-start;
}
.chat-input-tools .btn {
  font-size: var(--fs-xs);
  padding: var(--space-1) var(--space-3);
}

.chat-toolbar {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  margin-bottom: var(--space-2);
}

.assistant-key-row {
  display: flex;
  gap: var(--space-2);
  margin-bottom: var(--space-3);
}
.assistant-key-row select, .assistant-key-row input {
  flex: 1;
}
.recent-heading {
  font-size: var(--fs-xs);
  color: var(--ink-soft);
  margin-bottom: var(--space-2);
}
.recent-list {
  list-style: none;
  padding: 0;
  margin: 0;
}
.recent-item {
  padding: var(--space-1) var(--space-2);
  cursor: pointer;
  font-size: var(--fs-xs);
  color: var(--ink);
  border-radius: var(--radius-sm);
  transition: background var(--transition);
}
.recent-item:hover { background: var(--cream-card); }

.stop-generation-btn { display: none; }
.btn-danger { background: var(--red-stamp); color: #fff; border: none; }
.btn-danger:hover { background: #c0392b; }

.chat-suggestions {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1);
  padding: var(--space-2) 0;
}
.chat-suggestions .chip {
  font-size: 11px;
  padding: 4px 10px;
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft-line);
  border-radius: 50px;
  cursor: pointer;
  transition: border-color var(--transition);
}
.chat-suggestions .chip:hover { border-color: var(--green); }

.chat-attachments {
  display: flex;
  gap: var(--space-2);
  padding-bottom: var(--space-2);
  flex-wrap: wrap;
}
.file-tag {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  font-size: var(--fs-xs);
  font-weight: 600;
  padding: var(--space-1) var(--space-3);
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft);
  border-radius: 50px;
  color: var(--ink);
}
.file-tag svg { width: 14px; height: 14px; }
.file-remove {
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  color: var(--red-stamp);
  display: inline-flex;
  align-items: center;
}
.btn-attach {
  padding: var(--space-2) var(--space-3);
  display: flex;
  align-items: center;
  cursor: pointer;
}
.btn-attach svg { width: 18px; height: 18px; }
.chat-msg.has-file { padding-top: var(--space-2); }
.chat-msg .file-tag { margin-bottom: var(--space-2); }

/* Regenerate button */
.regenerate-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  background: transparent;
  border: 1px solid var(--kraft);
  color: var(--ink-soft);
  font-size: 11px;
  padding: 2px 8px;
  border-radius: 4px;
  cursor: pointer;
  margin-top: var(--space-2);
  margin-inline-start: var(--space-1);
  transition: color var(--transition), border-color var(--transition);
}
.regenerate-btn:hover { color: var(--green); border-color: var(--green); }
.regenerate-btn .icon svg { width: 13px; height: 13px; }

/* Copy button on bot messages */
.copy-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 4px;
  background: transparent;
  border: none;
  color: var(--ink-soft);
  font-size: 11px;
  padding: 2px 6px;
  border-radius: 4px;
  cursor: pointer;
  margin-top: var(--space-2);
  transition: color var(--transition), background var(--transition);
}
.copy-btn:hover { color: var(--green); background: rgba(31,111,80,0.08); }
.copy-btn .icon svg { width: 14px; height: 14px; }
.copy-btn.copied { color: var(--green); }

/* Markdown rendered styles inside bot messages */
.chat-msg.bot h1, .chat-msg.bot h2, .chat-msg.bot h3 {
  margin: var(--space-3) 0 var(--space-2);
  font-family: var(--font-display);
  line-height: 1.3;
}
.chat-msg.bot h1 { font-size: var(--fs-lg); }
.chat-msg.bot h2 { font-size: var(--fs-md); }
.chat-msg.bot h3 { font-size: var(--fs-base); }
.chat-msg.bot p { margin: var(--space-2) 0; }
.chat-msg.bot p:first-child { margin-top: 0; }
.chat-msg.bot p:last-child { margin-bottom: 0; }
.chat-msg.bot hr { margin: var(--space-3) 0; border: none; border-top: 2px solid var(--kraft-line); }
.chat-msg.bot pre {
  background: #1e1e2e;
  color: #cdd6f4;
  padding: var(--space-3);
  border-radius: var(--radius-md);
  overflow-x: auto;
  font-family: var(--font-mono);
  font-size: var(--fs-xs);
  margin: var(--space-2) 0;
  white-space: pre;
}
.chat-msg.bot code {
  background: var(--kraft);
  padding: 1px 4px;
  border-radius: 4px;
  font-family: var(--font-mono);
  font-size: .9em;
}
.chat-msg.bot pre code { background: none; padding: 0; font-size: var(--fs-xs); }
.chat-msg.bot blockquote {
  margin: var(--space-2) 0;
  padding: var(--space-2) var(--space-3);
  border-inline-start: 3px solid var(--gold);
  background: var(--cream-card);
  border-radius: var(--radius-sm);
  font-style: italic;
  color: var(--ink-soft);
}
.chat-msg.bot ul, .chat-msg.bot ol {
  margin: var(--space-2) 0;
  padding-inline-start: var(--space-5);
}
.chat-msg.bot li { margin: var(--space-1) 0; }
.chat-msg.bot a { color: var(--green); text-decoration: underline; }
.chat-msg.bot table {
  border-collapse: collapse;
  margin: var(--space-2) 0;
  width: 100%;
  font-size: var(--fs-sm);
}
.chat-msg.bot th, .chat-msg.bot td {
  border: 1px solid var(--kraft-line);
  padding: var(--space-2) var(--space-3);
  text-align: left;
}
html[dir="rtl"] .chat-msg.bot th, html[dir="rtl"] .chat-msg.bot td { text-align: right; }
.chat-msg.bot th { background: var(--cream-card); font-weight: 700; }
.chat-msg.bot .math-block { overflow-x: auto; margin: var(--space-2) 0; }
.chat-msg.bot .katex { font-size: 1.05em; }
.chat-msg.bot .katex-display > .katex { font-size: 1.15em; }
.chat-msg.bot .math-fallback { font-family: var(--font-mono); font-size: var(--fs-xs); color: var(--green); background: var(--green-bg); padding: 0.1em 0.3em; border-radius: var(--radius-sm); white-space: pre-wrap; }

.conv-sidebar {
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft-line);
  border-radius: var(--radius-md);
  margin-bottom: var(--space-2);
  overflow: hidden;
}
.conv-sidebar-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-2) var(--space-3);
  border-bottom: var(--border-w) solid var(--kraft-line);
  font-size: var(--fs-sm);
}
.conv-list {
  max-height: 200px;
  overflow-y: auto;
  padding: var(--space-1) 0;
}
.conv-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-2) var(--space-3);
  cursor: pointer;
  font-size: var(--fs-xs);
  border-bottom: 1px solid var(--kraft-line);
  transition: background var(--transition);
}
.conv-item:hover { background: var(--surface); }
.conv-item.active { background: var(--surface); font-weight: 700; }
.conv-item-title { flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.conv-item-actions { display: flex; gap: var(--space-1); flex-shrink: 0; }
.conv-item-actions button { padding: 2px 4px; font-size: 10px; background: none; border: 1px solid var(--kraft); border-radius: 4px; cursor: pointer; }
.saved-prompts-panel {
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft-line);
  border-radius: var(--radius-md);
  margin-bottom: var(--space-2);
  overflow: hidden;
}
.prompt-item {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-2) var(--space-3);
  cursor: pointer;
  font-size: var(--fs-xs);
  border-bottom: 1px solid var(--kraft-line);
  transition: background var(--transition);
}
.prompt-item:hover { background: var(--surface); }
.prompt-item-text { flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }

/* ============================================================
   ADMIN PANEL
   ============================================================ */
.admin-page {
  max-width: 1400px;
  margin: 0 auto;
  padding: var(--space-8) var(--space-5) var(--space-10);
}

.admin-lock {
  max-width: 420px;
  margin: var(--space-10) auto;
  text-align: center;
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft);
  border-radius: var(--radius-lg);
  padding: var(--space-8) var(--space-6);
}
.admin-lock svg { width: 48px; height: 48px; color: var(--gold); margin: 0 auto var(--space-4); }
.admin-lock-form {
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
  margin-top: var(--space-5);
}
.admin-lock-form input {
  padding: var(--space-3) var(--space-4);
  border: 2px solid var(--kraft);
  border-radius: var(--radius-md);
  background: var(--surface);
  color: var(--ink);
  text-align: center;
}
.admin-error {
  color: var(--red-stamp);
  font-size: var(--fs-sm);
  font-weight: 600;
  min-height: 1.2em;
}

.admin-section {
  background: var(--cream-card);
  border: var(--border-w) solid var(--kraft);
  border-radius: var(--radius-lg);
  padding: var(--space-6);
  margin-bottom: var(--space-5);
}
.admin-section h3 { font-size: var(--fs-md); margin-bottom: var(--space-4); display: flex; align-items: center; gap: var(--space-2); }

.form-row {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  margin-bottom: var(--space-4);
}
.form-row label { font-size: var(--fs-sm); font-weight: 700; color: var(--ink-soft); }
.form-row input, .form-row select, .form-row textarea {
  padding: var(--space-3) var(--space-4);
  border: 2px solid var(--kraft);
  border-radius: var(--radius-md);
  background: var(--surface);
  color: var(--ink);
  font-family: inherit;
}
.form-row textarea { min-height: 100px; resize: vertical; font-size: var(--fs-sm); }
.form-row input:focus, .form-row select:focus, .form-row textarea:focus { border-color: var(--green); }
.form-row-cols { display: grid; grid-template-columns: 1fr 1fr; gap: var(--space-4); }
@media (max-width: 600px) { .form-row-cols { grid-template-columns: 1fr; } }
.form-row-cols-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: var(--space-4); }
@media (max-width: 700px) { .form-row-cols-3 { grid-template-columns: 1fr; } }

.key-list { display: flex; flex-direction: column; gap: var(--space-3); }
.key-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
  padding: var(--space-3) var(--space-4);
  background: var(--surface);
  border: var(--border-w) solid var(--kraft-line);
  border-radius: var(--radius-md);
  flex-wrap: wrap;
}
.key-item-info { display: flex; flex-direction: column; gap: 2px; }
.key-item-provider { font-weight: 700; font-family: var(--font-display); }
.key-item-meta { font-size: var(--fs-xs); color: var(--ink-soft); font-family: var(--font-mono); }
.key-item-actions { display: flex; gap: var(--space-2); }
.badge-active {
  font-size: var(--fs-xs);
  font-weight: 700;
  color: var(--green);
  background: rgba(31,111,80,0.12);
  padding: 2px var(--space-2);
  border-radius: 50px;
}
.btn-sm { padding: var(--space-2) var(--space-3); font-size: var(--fs-xs); }
.btn-danger { background: transparent; border: 2px solid var(--red-stamp); color: var(--red-stamp); }
.btn-danger:hover { background: var(--red-stamp); color: #fff; }

.save-confirm {
  font-size: var(--fs-sm);
  color: var(--green);
  font-weight: 700;
  opacity: 0;
  transition: opacity var(--transition);
}
.save-confirm.show { opacity: 1; }

.admin-toprow { display: flex; align-items: center; justify-content: space-between; margin-bottom: var(--space-6); flex-wrap: wrap; gap: var(--space-3); }

/* ---- Admin tabs ---- */
.admin-tabs {
  display: flex;
  gap: var(--space-2);
  margin-bottom: var(--space-5);
  border-bottom: var(--border-w) solid var(--kraft-line);
}
.admin-tab-btn {
  padding: var(--space-3) var(--space-4);
  background: transparent;
  border: none;
  border-bottom: 3px solid transparent;
  font-weight: 700;
  font-size: var(--fs-sm);
  color: var(--ink-soft);
  transition: color var(--transition), border-color var(--transition);
}
.admin-tab-btn.active { color: var(--green); border-color: var(--green); }
.admin-tab-btn:hover { color: var(--green); }
.admin-tab-panel.hidden { display: none; }

/* ---- Doc manager table ---- */
.admin-doc-table-wrap {
  overflow-x: auto;
  margin-top: var(--space-4);
}
.admin-doc-table-wrap table {
  min-width: 1200px;
}
.admin-doc-table {
  width: 100%;
  border-collapse: collapse;
  font-size: var(--fs-sm);
}
.admin-doc-table th {
  text-align: left;
  padding: var(--space-2) var(--space-3);
  color: var(--ink-soft);
  font-size: var(--fs-xs);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  border-bottom: var(--border-w) solid var(--kraft-line);
}
html[dir="rtl"] .admin-doc-table th { text-align: right; }
.admin-doc-table th.sortable { cursor: pointer; user-select: none; }
.admin-doc-table th.sortable:hover { color: var(--green); }
.btn-source-eye { cursor:pointer; background:none; border:none; font-size:1.1rem; padding:2px 6px; border-radius:var(--radius-sm); transition:background 0.15s; }
.btn-source-eye:hover { background:var(--kraft-line); }
.btn-preview-pdf { cursor:pointer; background:none; border:none; font-size:1rem; padding:2px 4px; border-radius:var(--radius-sm); transition:background 0.15s; }
.btn-preview-pdf:hover { background:var(--kraft-line); }
.admin-doc-table td {
  padding: var(--space-3);
  border-bottom: 1px solid var(--kraft-line);
  vertical-align: middle;
}
.doc-table-title { font-weight: 600; max-width: 260px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.doc-table-actions { display: flex; gap: var(--space-1); white-space: nowrap; flex-shrink: 0; min-width: 100px; }
.local-tag {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  background: rgba(31,111,80,0.12);
  color: var(--green);
  padding: 1px 6px;
  border-radius: 50px;
  margin-inline-start: var(--space-2);
}

.admin-doc-search-row {
  display: flex;
  gap: var(--space-3);
  align-items: center;
  flex-wrap: wrap;
  justify-content: space-between;
}

.export-hint {
  font-size: var(--fs-xs);
  color: var(--ink-soft);
  margin-top: var(--space-2);
}

.doc-form-actions {
  display: flex;
  gap: var(--space-3);
  align-items: center;
  margin-top: var(--space-2);
}

.btn-ghost.active {
  background: var(--green-bg) !important;
  color: var(--green) !important;
  border-color: var(--green) !important;
}

/* Admin sub-tabs */
.admin-sub-tabs {
  display: flex;
  gap: 0;
  margin-bottom: var(--space-3);
  border-bottom: 2px solid var(--kraft-line);
}
.admin-sub-tab {
  padding: var(--space-2) var(--space-4);
  border: none;
  background: none;
  cursor: pointer;
  font-size: var(--fs-sm);
  font-weight: 600;
  color: var(--ink-soft);
  border-bottom: 2px solid transparent;
  margin-bottom: -2px;
  transition: color .15s, border-color .15s;
}
.admin-sub-tab:hover { color: var(--ink); }
.admin-sub-tab.active {
  color: var(--green);
  border-bottom-color: var(--green);
}

/* Admin collapsible sections */
.admin-collapse {
  border: var(--border-w) solid var(--kraft-line);
  border-radius: var(--radius-md);
  margin-bottom: var(--space-3);
  overflow: hidden;
  background: var(--surface);
}
.admin-collapse-summary {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-2) var(--space-3);
  cursor: pointer;
  font-size: var(--fs-sm);
  font-weight: 700;
  color: var(--ink);
  background: var(--cream-card);
  user-select: none;
  list-style: none;
}
.admin-collapse-summary::-webkit-details-marker { display: none; }
.admin-collapse-summary::before {
  content: '\25B6';
  font-size: 10px;
  color: var(--ink-soft);
  transition: transform .2s;
}
.admin-collapse[open] > .admin-collapse-summary::before { transform: rotate(90deg); }
.admin-collapse-body {
  padding: var(--space-3);
}

/* Backup tooltip */
.db-backup-item { position: relative; }
.db-backup-tooltip {
  display: none;
  position: fixed;
  z-index: 10000;
  background: var(--ink);
  color: #fff;
  padding: var(--space-2) var(--space-3);
  border-radius: var(--radius-md);
  font-size: var(--fs-xs);
  line-height: 1.5;
  white-space: nowrap;
  pointer-events: none;
  box-shadow: 0 4px 12px rgba(0,0,0,.25);
  max-width: min(90vw, 400px);
  overflow: hidden;
}
.db-backup-tooltip.show { display: block; }

/* ============================================================
   PASSWORD TOGGLE (eye icon)
   ============================================================ */
.pwd-toggle-wrap {
  position: relative;
  display: flex;
  align-items: center;
}
.pwd-toggle-wrap {
  position: relative;
  display: flex;
  align-items: stretch;
}
.pwd-toggle-wrap input {
  padding-right: 32px;
  width: 100%;
  box-sizing: border-box;
}
.pwd-toggle-btn {
  position: absolute;
  right: 2px;
  top: 2px;
  bottom: 2px;
  background: none;
  border: none;
  cursor: pointer;
  padding: 2px 6px;
  color: var(--ink-soft);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1;
  border-radius: var(--radius-sm);
}
.pwd-toggle-btn:hover { color: var(--ink); background: rgba(0,0,0,.04); }
.pwd-toggle-btn .icon svg { width: 18px; height: 18px; display: block; }

/* ============================================================
   Blogger-specific fixes
   ============================================================ */
#main-section { display: none; }
body { margin: 0 !important; padding: 0 !important; }

[data-theme="dark"] body { background-color: var(--paper) !important; }
[data-theme="dark"] body > div:not([id^="fp-view"]):not([id="header-root"]):not([id="footer-root"]):not(.skip-link) {
  background: transparent !important;
}
[data-theme="dark"] a { color: var(--green) !important; }
[data-theme="dark"] .brand-name { color: var(--ink) !important; }
[data-theme="dark"] .brand-tagline { color: var(--ink-soft) !important; }
[data-theme="dark"] .nav-link.active { color: var(--green) !important; }
[data-theme="dark"] h1, [data-theme="dark"] h2, [data-theme="dark"] h3, [data-theme="dark"] h4 { color: var(--ink) !important; }
[data-theme="dark"] label, [data-theme="dark"] .export-hint { color: var(--ink-soft) !important; }
[data-theme="dark"] .toast { background: var(--ink) !important; color: var(--paper) !important; }
[data-theme="dark"] .local-tag { background: var(--gold) !important; color: var(--ink) !important; }

body.script:
//
  window.INRY_BASE_URL = 'https://cdn.jsdelivr.net/gh/droidapk1002-beep/inry-biblio-assets@main/repo/';
  window.INRY_ROUTES = { home: '#home', library: '#library', assistant: '#assistant', admin: '#admin' };
//

//
(function(){
  var _orig = window.openDocModal;
  if(typeof _orig !== 'function') return;
  window.openDocModal = function(docId){
    _orig(docId);
    var pv = document.getElementById('modal-preview');
    if(!pv) return;
    var fix = function(){
      var ifr = pv.querySelector('iframe');
      if(!ifr) return;
      var s = ifr.src || '';
      if(s.indexOf('docs.google.com/gview') !== -1){
        var m = s.match(/id=([^&]+)/);
        if(m) ifr.src = 'https://drive.google.com/file/d/' + m[1] + '/preview';
      }
    };
    fix();
    setTimeout(fix, 300);
  };
})();
//

//
/* ============================================================
   ADMIN DOCUMENT MANAGER — add / edit / delete documents
   ============================================================ */

const LOCAL_DOCS_KEY = 'inry_local_docs';
const DELETED_DOCS_KEY = 'inry_deleted_doc_ids';
const PENDING_DOCS_KEY = 'inry_pending_docs';

let sortState = { key: 'id', dir: 'desc' };

function getLocalDocs() {
  try { return JSON.parse(localStorage.getItem(LOCAL_DOCS_KEY) || '[]'); }
  catch { return []; }
}
function saveLocalDocs(docs) {
  localStorage.setItem(LOCAL_DOCS_KEY, JSON.stringify(docs));
}
function getDeletedIds() {
  try { return JSON.parse(localStorage.getItem(DELETED_DOCS_KEY) || '[]'); }
  catch { return []; }
}
function saveDeletedIds(ids) {
  localStorage.setItem(DELETED_DOCS_KEY, JSON.stringify(ids));
}
function getPendingDocs() {
  try { return JSON.parse(localStorage.getItem(PENDING_DOCS_KEY) || '[]'); }
  catch { return []; }
}
function savePendingDocs(docs) {
  localStorage.setItem(PENDING_DOCS_KEY, JSON.stringify(docs));
}
function approvePendingDoc(docId) {
  const pending = getPendingDocs();
  const idx = pending.findIndex(d => d.id === docId);
  if (idx === -1) return;
  const [doc] = pending.splice(idx, 1);
  savePendingDocs(pending);
  upsertLocalDoc(doc);
  applyLocalDocOverrides();
  renderAdminDocTable();
}
function rejectPendingDoc(docId) {
  const pending = getPendingDocs();
  const filtered = pending.filter(d => d.id !== docId);
  savePendingDocs(filtered);
  renderAdminDocTable();
}
function approveAllPending() {
  const pending = getPendingDocs();
  if (!pending.length) return;
  pending.forEach(d => upsertLocalDoc(d));
  savePendingDocs([]);
  applyLocalDocOverrides();
  renderAdminDocTable();
  showToast(pending.length + ' document(s) validé(s)');
}

function applyLocalDocOverrides() {
  if (!APP.db || !APP.db.documents) return;
  const deleted = new Set(getDeletedIds());
  const localDocs = getLocalDocs();
  const localIds = new Set(localDocs.map(d => d.id));
  const base = APP.db.documents.filter(d => !deleted.has(d.id) && !localIds.has(d.id));
  APP.db.documents = [...base, ...localDocs.filter(d => !deleted.has(d.id))];
}

function upsertLocalDoc(doc) {
  const docs = getLocalDocs();
  const idx = docs.findIndex(d => d.id === doc.id);
  if (idx >= 0) docs[idx] = doc;
  else docs.push(doc);
  saveLocalDocs(docs);
  const deleted = getDeletedIds().filter(id => id !== doc.id);
  saveDeletedIds(deleted);
  scheduleAutoPush();
}

function deleteDocEverywhere(id) {
  saveLocalDocs(getLocalDocs().filter(d => d.id !== id));
  const deleted = getDeletedIds();
  if (!deleted.includes(id)) { deleted.push(id); saveDeletedIds(deleted); }
  scheduleAutoPush();
}

function nextDocId(allDocs) {
  const nums = allDocs.map(d => parseInt((d.id || '').replace('doc-',''), 10)).filter(n => !isNaN(n));
  const max = nums.length ? Math.max(...nums) : 0;
  return 'doc-' + String(max + 1).padStart(4, '0');
}

let editingDocId = null;
let editingIsPending = false;
let titleAutoFill = true;
let descAutoFill = true;
let titleTimer = null;
let descTimer = null;

function initDocManager() {
  if (!APP.db) { console.error('[INRY-Biblio] APP.db est vide'); return; }
  populateDocFormSelects();
  renderAdminDocTable();
  wireDocManagerEvents();
  wireImportBackupUI();
  wireAutoBackupUI();
  startAutoBackup();
  wireGithubSync();
}

function populateDocFormSelects() {
  const levelSel = document.getElementById('doc-form-level');
  const streamSel = document.getElementById('doc-form-stream');
  const subjectSel = document.getElementById('doc-form-subject');
  const typeSel = document.getElementById('doc-form-type');
  const hostSel = document.getElementById('doc-form-host');
  const wilayaSel = document.getElementById('doc-form-wilaya');
  const trimestreSel = document.getElementById('doc-form-trimestre');
  if (!levelSel || !streamSel || !subjectSel || !typeSel || !hostSel) return;
  levelSel.innerHTML = APP.db.levels.map(grp => '<optgroup label="' + escapeAttr(localized(grp.name)) + '">' + grp.years.map(y => '<option value="' + escapeAttr(y.id) + '">' + escapeHTML(localized(y.name)) + '</option>').join('') + '</optgroup>').join('');
  streamSel.innerHTML = '<option value="">—</option>' + APP.db.streams.map(s => '<option value="' + escapeAttr(s.id) + '">' + escapeHTML(localized(s.name)) + '</option>').join('');
  subjectSel.innerHTML = APP.db.subjects.map(s => '<option value="' + escapeAttr(s.id) + '">' + escapeHTML(localized(s.name)) + '</option>').join('');
  typeSel.innerHTML = APP.db.documentTypes.map(ty => '<option value="' + escapeAttr(ty.id) + '">' + escapeHTML(localized(ty.name)) + '</option>').join('');
  hostSel.innerHTML = '<option value="drive">Google Drive</option><option value="mega">Mega</option><option value="other">Autre</option>';
  if (wilayaSel) { const wl = APP.db.wilayas || []; wilayaSel.innerHTML = '<option value="">— ' + t('admin.noWilaya') + '</option><option value="National">' + t('admin.nationalWilaya') + '</option>' + wl.map(w => '<option value="' + escapeAttr(localized(w.name)) + '">' + escapeHTML(w.code) + ' — ' + escapeHTML(localized(w.name)) + '</option>').join(''); }
  if (trimestreSel) { const tl = APP.db.trimestres || []; trimestreSel.innerHTML = '<option value="">— ' + t('admin.noTrimestre') + '</option>' + tl.map(tr => '<option value="' + escapeAttr(tr.id) + '">' + escapeHTML(localized(tr.name)) + '</option>').join(''); }
}

function renderAdminDocTable() {
  const tbody = document.getElementById('admin-doc-table-body');
  const searchVal = (document.getElementById('admin-doc-search')?.value || '').toLowerCase().trim();
  const pendingDocs = getPendingDocs();
  const hiddenIds = getHiddenIds();
  let docs = [...APP.db.documents];
  const sk = sortState.key, sd = sortState.dir;
  docs.sort((a, b) => { let va, vb; if (sk === 'id') { va = parseInt(a.id.replace('doc-',''), 10) || 0; vb = parseInt(b.id.replace('doc-',''), 10) || 0; } else if (sk === 'title') { va = (localized(a.title) || '').toLowerCase(); vb = (localized(b.title) || '').toLowerCase(); } else { va = (a[sk] != null ? String(a[sk]) : '').toLowerCase(); vb = (b[sk] != null ? String(b[sk]) : '').toLowerCase(); } if (va < vb) return sd === 'asc' ? -1 : 1; if (va > vb) return sd === 'asc' ? 1 : -1; return 0; });
  if (searchVal) { docs = docs.filter(d => { const hay = [localized(d.title), d.id, d.subject, d.level].join(' ').toLowerCase(); return hay.includes(searchVal); }); }
  const selAllChecked = localStorage.getItem('_inry_select_all') === 'true' ? 'checked' : '';
  let html = '';
  html += '<tr class="selection-toolbar"><td colspan="8" style="padding:0.5rem 1rem;background:var(--surface);border-bottom:1px solid var(--kraft-line);"><div style="display:flex;gap:var(--space-2);align-items:center;justify-content:center;flex-wrap:wrap;"><button class="btn btn-ghost btn-xs" id="select-all-btn">☐ Tout</button><button class="btn btn-ghost btn-xs" id="deselect-all-btn">☐ Aucun</button><span style="color:var(--ink-soft);font-size:var(--fs-xs);" id="sel-count"></span><button class="btn btn-danger btn-xs" id="delete-selected-btn" style="display:none;">🗑 Supprimer</button><button class="btn btn-secondary btn-xs" id="hide-selected-btn" style="display:none;">👁 Masquer</button><button class="btn btn-secondary btn-xs" id="unhide-selected-btn" style="display:none;">👁 Afficher</button><button class="btn btn-primary btn-xs" id="bulk-edit-btn" style="display:none;">✏️ Modifier</button></div></td></tr>';
  html += '<tr id="bulk-edit-panel" style="display:none;"><td colspan="8" style="padding:0.75rem 1rem;background:var(--surface-alt,#f5f0e8);border-bottom:2px solid var(--kraft-line);"><div style="display:flex;gap:var(--space-3);align-items:flex-end;flex-wrap:wrap;"><div style="font-weight:700;font-size:var(--fs-sm);width:100%;">✏️ Modifier la sélection — ne coche que les champs à changer :</div><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-level"> Niveau <select id="bulk-val-level" disabled style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-stream"> Filière <select id="bulk-val-stream" disabled style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-subject"> Matière <select id="bulk-val-subject" disabled style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-type"> Type <select id="bulk-val-type" disabled style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-host"> Hébergeur <input type="text" id="bulk-val-host" disabled list="bulk-datalist-host" placeholder="Google Drive / Mega…" style="display:block;margin-top:2px;width:140px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-wilaya"> Wilaya <select id="bulk-val-wilaya" disabled style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-trimestre"> Trimestre <select id="bulk-val-trimestre" disabled style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-year"> Année <input type="number" id="bulk-val-year" disabled placeholder="2025" min="2000" max="2099" style="display:block;margin-top:2px;width:90px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-source"> Source <input type="text" id="bulk-val-source" disabled placeholder="…" style="display:block;margin-top:2px;width:120px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-url-source"> URL Source <input type="url" id="bulk-val-url-source" disabled list="bulk-datalist-url-source" placeholder="https://…" style="display:block;margin-top:2px;width:180px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-url-pdf"> URL PDF <input type="url" id="bulk-val-url-pdf" disabled list="bulk-datalist-url-pdf" placeholder="https://…" style="display:block;margin-top:2px;width:180px;"></label><button class="btn btn-primary btn-xs" id="bulk-apply-btn">✅ Appliquer</button><button class="btn btn-ghost btn-xs" id="bulk-cancel-btn">✖ Annuler</button><span id="bulk-confirm" style="color:var(--green);font-size:var(--fs-xs);font-weight:600;"></span><datalist id="bulk-datalist-host"><option value="Google Drive"><option value="Mega"><option value="Autre"></datalist><datalist id="bulk-datalist-url-source"></datalist><datalist id="bulk-datalist-url-pdf"></datalist></div></td></tr>';

  if (pendingDocs.length) {
    html += '<tr class="pending-section-header"><td colspan="8" style="padding:0.75rem 1rem;background:var(--gold);color:var(--ink);font-weight:700;">⏳ ' + pendingDocs.length + ' document(s) en attente de validation</td></tr>';
    pendingDocs.forEach(doc => { const subject = APP.db.subjects.find(s => s.id === doc.subject); const typeName = APP.db.documentTypes.find(ty => ty.id === doc.type); const isHidden = hiddenIds.includes(doc.id); html += '<tr data-doc-id="' + escapeAttr(doc.id) + '" style="background:var(--cream);' + (isHidden ? 'opacity:0.5;' : '') + '"><td><input type="checkbox" class="doc-select-cb" data-doc-id="' + escapeAttr(doc.id) + '" ' + selAllChecked + '></td><td class="doc-table-title">' + escapeHTML(localized(doc.title)) + ' <span class="local-tag" style="background:var(--gold);color:var(--ink);">en attente</span>' + (isHidden ? ' <span class="local-tag" style="background:var(--ink-soft);">masqué</span>' : '') + '</td><td>' + escapeHTML(subject ? localized(subject.name) : doc.subject) + '</td><td>' + escapeHTML(typeName ? localized(typeName.name) : doc.type) + '</td><td>—</td><td class="ltr-only">' + escapeHTML(doc.year || '—') + '</td><td style="text-transform:capitalize;">' + escapeHTML(doc.host) + '</td><td style="text-transform:capitalize;">' + escapeHTML(doc.source || '—') + '</td><td style="white-space:nowrap;">' + (doc.urlSource ? '<button class="btn-source-eye" data-url="' + escapeAttr(doc.urlSource) + '" title="Voir la source">📄</button>' : '') + (doc.previewUrl || doc.downloadUrl || doc.urlPdf ? '<button class="btn-preview-pdf" data-url="' + escapeAttr(doc.previewUrl || doc.downloadUrl || doc.urlPdf) + '" title="Aperçu PDF">👁</button>' : '') + ((!doc.urlSource && !doc.previewUrl && !doc.urlPdf && !doc.downloadUrl) ? '—' : '') + '</td><td class="doc-table-actions"><button class="btn btn-secondary btn-sm edit-pending-btn" data-doc-id="' + escapeAttr(doc.id) + '">' + icon('settings') + '</button><button class="btn btn-primary btn-sm approve-pending-btn" data-doc-id="' + escapeAttr(doc.id) + '">✓ Valider</button><button class="btn btn-danger btn-sm reject-pending-btn" data-doc-id="' + escapeAttr(doc.id) + '">✕ Rejeter</button></td></tr>'; });
    html += '<tr><td colspan="10" style="padding:0.5rem 1rem;"><button class="btn btn-primary btn-sm" id="approve-all-pending-btn">✓ Tout valider</button></td></tr>';
  }

  if (docs.length) {
    html += '<tr class="pending-section-header"><td colspan="10" style="padding:0.75rem 1rem;background:var(--kraft);font-weight:600;">✅ Documents publiés (' + docs.length + ')</td></tr>';
    html += docs.map(doc => { const subject = APP.db.subjects.find(s => s.id === doc.subject); const typeName = APP.db.documentTypes.find(ty => ty.id === doc.type); const trimestreName = APP.db.trimestres?.find(tr => tr.id === doc.trimestre); const isLocal = getLocalDocs().some(d => d.id === doc.id); const isHidden = hiddenIds.includes(doc.id); return '<tr data-doc-id="' + escapeAttr(doc.id) + '"' + (isHidden ? ' style="opacity:0.5;"' : '') + '><td><input type="checkbox" class="doc-select-cb" data-doc-id="' + escapeAttr(doc.id) + '" ' + selAllChecked + '></td><td class="doc-table-title">' + escapeHTML(localized(doc.title)) + ' ' + (isLocal ? '<span class="local-tag">local</span>' : '') + (isHidden ? ' <span class="local-tag" style="background:var(--ink-soft);">masqué</span>' : '') + '</td><td>' + escapeHTML(subject ? localized(subject.name) : '—') + '</td><td>' + escapeHTML(typeName ? localized(typeName.name) : doc.type) + '</td><td>' + escapeHTML(trimestreName ? localized(trimestreName.name) : '—') + '</td><td class="ltr-only">' + escapeHTML(doc.year || '—') + '</td><td style="text-transform:capitalize;">' + escapeHTML(doc.host) + '</td><td style="text-transform:capitalize;">' + escapeHTML(doc.source || '—') + '</td><td style="white-space:nowrap;">' + (doc.urlSource ? '<button class="btn-source-eye" data-url="' + escapeAttr(doc.urlSource) + '" title="Voir la source">📄</button>' : '') + (doc.previewUrl || doc.downloadUrl || doc.urlPdf ? '<button class="btn-preview-pdf" data-url="' + escapeAttr(doc.previewUrl || doc.downloadUrl || doc.urlPdf) + '" title="Aperçu PDF">👁</button>' : '') + ((!doc.urlSource && !doc.previewUrl && !doc.urlPdf && !doc.downloadUrl) ? '—' : '') + '</td><td class="doc-table-actions"><button class="btn btn-secondary btn-sm edit-doc-btn" data-doc-id="' + escapeAttr(doc.id) + '">' + icon('settings') + '</button><button class="btn btn-danger btn-sm delete-doc-btn" data-doc-id="' + escapeAttr(doc.id) + '">' + icon('trash') + '</button></td></tr>'; }).join('');
  }

  if (!html) { html = '<tr><td colspan="10" style="text-align:center; padding:1.5rem; color:var(--ink-soft);">' + t('empty.title') + '</td></tr>'; }
  tbody.innerHTML = html;

  const selCountEl = document.getElementById('sel-count');
  const deleteSelBtn = document.getElementById('delete-selected-btn');
  const hideSelBtn = document.getElementById('hide-selected-btn');
  const unhideSelBtn = document.getElementById('unhide-selected-btn');
  const bulkEditBtn = document.getElementById('bulk-edit-btn');
  const bulkPanel = document.getElementById('bulk-edit-panel');

  function updateSelectionUI() {
    const checked = tbody.querySelectorAll('.doc-select-cb:checked');
    const count = checked.length;
    const hIds = getHiddenIds();
    const hasHidden = [...checked].some(cb => hIds.includes(cb.dataset.docId));
    const hasVisible = [...checked].some(cb => !hIds.includes(cb.dataset.docId));
    if (selCountEl) selCountEl.textContent = count ? count + ' sélectionné(s)' : '';
    if (deleteSelBtn) { deleteSelBtn.disabled = count === 0; deleteSelBtn.style.display = count === 0 ? 'none' : ''; }
    if (hideSelBtn) { hideSelBtn.disabled = count === 0; hideSelBtn.style.display = hasVisible && count > 0 ? '' : 'none'; }
    if (unhideSelBtn) { unhideSelBtn.style.display = hasHidden ? '' : 'none'; }
    if (bulkEditBtn) { bulkEditBtn.disabled = count === 0; bulkEditBtn.style.display = count === 0 ? 'none' : ''; }
  }

  tbody.querySelectorAll('.doc-select-cb').forEach(cb => { cb.addEventListener('change', updateSelectionUI); });
  document.getElementById('select-all-btn')?.addEventListener('click', () => { tbody.querySelectorAll('.doc-select-cb').forEach(cb => { cb.checked = true; }); localStorage.setItem('_inry_select_all', 'true'); updateSelectionUI(); });
  document.getElementById('deselect-all-btn')?.addEventListener('click', () => { tbody.querySelectorAll('.doc-select-cb').forEach(cb => { cb.checked = false; }); localStorage.setItem('_inry_select_all', 'false'); updateSelectionUI(); });

  if (deleteSelBtn) { deleteSelBtn.addEventListener('click', () => { const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId); if (!window.confirm('Supprimer ' + ids.length + ' document(s) définitivement ?')) return; ids.forEach(id => { deleteDocEverywhere(id); const p = getPendingDocs().filter(d => d.id !== id); savePendingDocs(p); }); applyLocalDocOverrides(); renderAdminDocTable(); showToast(ids.length + ' document(s) supprimé(s)'); }); }
  if (hideSelBtn) { hideSelBtn.addEventListener('click', () => { const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId); const hidden = getHiddenIds(); ids.forEach(id => { if (!hidden.includes(id)) hidden.push(id); }); saveHiddenIds(hidden); renderAdminDocTable(); showToast(ids.length + ' document(s) masqué(s)'); }); }
  if (unhideSelBtn) { unhideSelBtn.addEventListener('click', () => { const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId); const hidden = getHiddenIds().filter(id => !ids.includes(id)); saveHiddenIds(hidden); renderAdminDocTable(); showToast(ids.length + ' document(s) ré-affiché(s)'); }); }

  if (bulkEditBtn && bulkPanel) {
    const bL = document.getElementById('bulk-val-level'), bS = document.getElementById('bulk-val-stream'), bSu = document.getElementById('bulk-val-subject'), bT = document.getElementById('bulk-val-type'), bulkHost = document.getElementById('bulk-val-host'), bW = document.getElementById('bulk-val-wilaya'), bTr = document.getElementById('bulk-val-trimestre'), bY = document.getElementById('bulk-val-year'), bSrc = document.getElementById('bulk-val-source'), bUS = document.getElementById('bulk-val-url-source'), bUP = document.getElementById('bulk-val-url-pdf');
    if (bL) bL.innerHTML = '<option value="">— choisir —</option>' + (APP.db.levels||[]).flatMap(grp => grp.years.map(y => '<option value="' + escapeAttr(y.id) + '">' + escapeHTML(localized(y.name)) + '</option>')).join('');
    if (bS) bS.innerHTML = '<option value="">— choisir —</option>' + (APP.db.streams||[]).map(s => '<option value="' + escapeAttr(s.id) + '">' + escapeHTML(localized(s.name)) + '</option>').join('');
    if (bSu) bSu.innerHTML = '<option value="">— choisir —</option>' + (APP.db.subjects||[]).map(s => '<option value="' + escapeAttr(s.id) + '">' + escapeHTML(localized(s.name)) + '</option>').join('');
    if (bT) bT.innerHTML = '<option value="">— choisir —</option>' + (APP.db.documentTypes||[]).map(ty => '<option value="' + escapeAttr(ty.id) + '">' + escapeHTML(localized(ty.name)) + '</option>').join('');
    if (bW) bW.innerHTML = '<option value="">— choisir —</option><option value="National">National</option>' + (APP.db.wilayas||[]).map(w => '<option value="' + escapeAttr(localized(w.name)) + '">' + escapeHTML(w.code) + ' — ' + escapeHTML(localized(w.name)) + '</option>').join('');
    if (bTr) bTr.innerHTML = '<option value="">— choisir —</option>' + (APP.db.trimestres||[]).map(tr => '<option value="' + escapeAttr(tr.id) + '">' + escapeHTML(localized(tr.name)) + '</option>').join('');
    const urlSourceVals = [...new Set((APP.db.documents||[]).map(d => d.urlSource).filter(Boolean))];
    const urlPdfVals = [...new Set((APP.db.documents||[]).map(d => d.previewUrl || d.downloadUrl || d.urlPdf).filter(Boolean))];
    const dlUrlSource = document.getElementById('bulk-datalist-url-source');
    const dlUrlPdf = document.getElementById('bulk-datalist-url-pdf');
    if (dlUrlSource) dlUrlSource.innerHTML = urlSourceVals.map(u => '<option value="' + escapeAttr(u) + '">').join('');
    if (dlUrlPdf) dlUrlPdf.innerHTML = urlPdfVals.map(u => '<option value="' + escapeAttr(u) + '">').join('');
    ['bulk-chk-level','bulk-chk-stream','bulk-chk-subject','bulk-chk-type','bulk-chk-host','bulk-chk-wilaya','bulk-chk-trimestre','bulk-chk-year','bulk-chk-source','bulk-chk-url-source','bulk-chk-url-pdf'].forEach(cId => { const c = document.getElementById(cId); if (c) c.addEventListener('change', () => { const ctrl = c.parentElement.querySelector('select, input[type="number"], input[type="text"], input[type="url"]'); if (ctrl) ctrl.disabled = !c.checked; }); });
    bulkEditBtn.addEventListener('click', () => { bulkPanel.style.display = bulkPanel.style.display === 'none' ? '' : 'none'; const bc = document.getElementById('bulk-confirm'); if (bc) bc.textContent = ''; });
    document.getElementById('bulk-cancel-btn')?.addEventListener('click', () => { bulkPanel.style.display = 'none'; });
    document.getElementById('bulk-apply-btn')?.addEventListener('click', () => {
      const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId);
      if (!ids.length) return;
      const fields = {};
      if (document.getElementById('bulk-chk-level')?.checked) fields.level = bL.value;
      if (document.getElementById('bulk-chk-stream')?.checked) fields.stream = bS.value || null;
      if (document.getElementById('bulk-chk-subject')?.checked) fields.subject = bSu.value;
      if (document.getElementById('bulk-chk-type')?.checked) fields.type = bT.value;
      if (document.getElementById('bulk-chk-host')?.checked && bulkHost.value.trim()) fields.host = bulkHost.value.trim();
      if (document.getElementById('bulk-chk-wilaya')?.checked) fields.wilaya = bW.value || null;
      if (document.getElementById('bulk-chk-trimestre')?.checked) fields.trimestre = bTr.value || null;
      if (document.getElementById('bulk-chk-year')?.checked && bY.value) fields.year = parseInt(bY.value, 10);
      if (document.getElementById('bulk-chk-source')?.checked && bSrc.value.trim()) fields.source = bSrc.value.trim();
      if (document.getElementById('bulk-chk-url-source')?.checked && bUS.value.trim()) fields.urlSource = bUS.value.trim();
      if (document.getElementById('bulk-chk-url-pdf')?.checked && bUP.value.trim()) fields.urlPdf = bUP.value.trim();
      if (!Object.keys(fields).length) { showToast('Coche au moins un champ'); return; }
      let count = 0;
      (APP.db.documents||[]).forEach(doc => { if (ids.includes(doc.id)) { Object.assign(doc, fields); count++; } });
      try { const pending = getPendingDocs(); if (pending.length) { pending.forEach(doc => { if (ids.includes(doc.id)) { Object.assign(doc, fields); count++; } }); savePendingDocs(pending); } } catch(e) {}
      renderAdminDocTable();
      const bc = document.getElementById('bulk-confirm');
      if (bc) bc.textContent = '✅ ' + count + ' document(s) modifié(s)';
      showToast(count + ' document(s) modifié(s)');
    });
  }

  tbody.querySelectorAll('.edit-doc-btn').forEach(btn => { btn.addEventListener('click', () => openDocFormForEdit(btn.dataset.docId)); });
  tbody.querySelectorAll('.delete-doc-btn').forEach(btn => { btn.addEventListener('click', () => confirmDeleteDoc(btn.dataset.docId)); });
  tbody.querySelectorAll('.edit-pending-btn').forEach(btn => { btn.addEventListener('click', () => openDocFormForEdit(btn.dataset.docId)); });
  tbody.querySelectorAll('.approve-pending-btn').forEach(btn => { btn.addEventListener('click', () => approvePendingDoc(btn.dataset.docId)); });
  tbody.querySelectorAll('.reject-pending-btn').forEach(btn => { btn.addEventListener('click', () => rejectPendingDoc(btn.dataset.docId)); });
  const approveAllBtn = document.getElementById('approve-all-pending-btn');
  if (approveAllBtn) approveAllBtn.addEventListener('click', approveAllPending);
  tbody.querySelectorAll('.btn-source-eye').forEach(btn => { btn.addEventListener('click', () => window.open(btn.dataset.url, '_blank')); });
  tbody.querySelectorAll('.btn-preview-pdf').forEach(btn => { btn.addEventListener('click', () => window.open(btn.dataset.url, '_blank')); });
  updateSelectionUI();
  updateSortIndicators();
  wireSortHeaders();
}

function updateSortIndicators() { document.querySelectorAll('.admin-doc-table th.sortable').forEach(th => { const key = th.dataset.sort; const text = th.textContent.replace(/[▲▼].*$/, '').trim(); th.textContent = key === sortState.key ? text + ' ' + (sortState.dir === 'asc' ? '▲' : '▼') : text; }); }
function wireSortHeaders() { document.querySelectorAll('.admin-doc-table th.sortable').forEach(th => { th.removeEventListener('click', sortClickHandler); th.addEventListener('click', sortClickHandler); }); }
function sortClickHandler(e) { const key = e.currentTarget.dataset.sort; if (sortState.key === key) { sortState.dir = sortState.dir === 'asc' ? 'desc' : 'asc'; } else { sortState.key = key; sortState.dir = 'asc'; } renderAdminDocTable(); }

function openDocFormForEdit(docId) {
  let doc = APP.db.documents.find(d => d.id === docId);
  editingIsPending = false;
  if (!doc) { doc = getPendingDocs().find(d => d.id === docId); if (!doc) return; editingIsPending = true; }
  editingDocId = docId;
  titleAutoFill = true; descAutoFill = true;
  ['doc-form-title-ar','doc-form-title-en','doc-form-desc-ar','doc-form-desc-en'].forEach(id => { const el = document.getElementById(id); if (el) el.dataset.autofilled = 'true'; });
  document.getElementById('doc-form-title-fr').value = doc.title.fr || '';
  document.getElementById('doc-form-title-ar').value = doc.title.ar || '';
  document.getElementById('doc-form-title-en').value = doc.title.en || '';
  document.getElementById('doc-form-desc-fr').value = doc.description?.fr || '';
  document.getElementById('doc-form-desc-ar').value = doc.description?.ar || '';
  document.getElementById('doc-form-desc-en').value = doc.description?.en || '';
  if (doc.title.fr) document.getElementById('doc-form-title-fr').dispatchEvent(new Event('input', { bubbles: true }));
  if (doc.description?.fr) document.getElementById('doc-form-desc-fr').dispatchEvent(new Event('input', { bubbles: true }));
  document.getElementById('doc-form-level').value = doc.level || '';
  document.getElementById('doc-form-stream').value = doc.stream || '';
  document.getElementById('doc-form-subject').value = doc.subject || '';
  document.getElementById('doc-form-type').value = doc.type || '';
  document.getElementById('doc-form-year').value = doc.year || '';
  document.getElementById('doc-form-trimestre').value = doc.trimestre || '';
  document.getElementById('doc-form-wilaya').value = doc.wilaya || '';
  document.getElementById('doc-form-pages').value = doc.pages || '';
  document.getElementById('doc-form-size').value = doc.size || '';
  document.getElementById('doc-form-host').value = doc.host || 'drive';
  document.getElementById('doc-form-preview-url').value = doc.previewUrl || '';
  document.getElementById('doc-form-download-url').value = doc.downloadUrl || '';
  document.getElementById('doc-form-source').value = doc.source || '';
  document.getElementById('doc-form-url-source').value = doc.urlSource || '';
  document.getElementById('doc-form-url-pdf').value = doc.urlPdf || '';
  document.getElementById('doc-form-title-heading').textContent = t('admin.editDoc');
  document.getElementById('doc-form-submit-btn').textContent = t('admin.saveChanges');
  document.querySelectorAll('.admin-sub-tab').forEach(function(b) { b.classList.remove('active'); });
  document.querySelector('.admin-sub-tab[data-subtab="docs-add"]')?.classList.add('active');
  document.querySelectorAll('#tab-panel-docs .admin-sub-panel').forEach(function(p) { p.classList.add('hidden'); });
  document.getElementById('sub-panel-docs-add')?.classList.remove('hidden');
}

function resetDocForm() {
  editingDocId = null; editingIsPending = false;
  document.getElementById('doc-form').reset();
  document.getElementById('doc-form-title-heading').textContent = t('admin.addDoc');
  document.getElementById('doc-form-submit-btn').textContent = t('admin.save');
  titleAutoFill = true; descAutoFill = true;
  ['doc-form-title-ar','doc-form-title-en','doc-form-desc-ar','doc-form-desc-en'].forEach(id => { const el = document.getElementById(id); if (el) { el.dataset.autofilled = 'false'; el.placeholder = ''; } });
  if (titleTimer) clearTimeout(titleTimer);
  if (descTimer) clearTimeout(descTimer);
}

function confirmDeleteDoc(docId) {
  let doc = APP.db.documents.find(d => d.id === docId);
  if (!doc) doc = getPendingDocs().find(d => d.id === docId);
  if (!doc) return;
  if (!window.confirm(t('admin.confirmDelete') + '\n\n"' + localized(doc.title) + '"')) return;
  deleteDocEverywhere(docId); applyLocalDocOverrides(); renderAdminDocTable(); showToast(t('admin.docDeleted'));
  if (editingDocId === docId) resetDocForm();
}

async function tryFetchFileSize(url) { if (!url) return null; try { const res = await fetch(url, { method: 'HEAD' }); const len = res.headers.get('Content-Length'); if (len && parseInt(len) > 0) return formatFileSize(parseInt(len)); } catch {} return null; }
async function tryFetchPageCount(url) { if (!url) return null; try { const res = await fetch(url, { headers: { Range: 'bytes=0-15360' } }); const text = await res.text(); const m = text.match(/\/Type\s*\/Pages[^>]*\/Count\s+(\d+)/); if (m && m[1]) { const c = parseInt(m[1], 10); if (c > 0 && c < 500) return c; } } catch {} return null; }
function formatFileSize(bytes) { if (bytes < 1024) return bytes + ' B'; if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB'; if (bytes < 1073741824) return (bytes / 1048576).toFixed(1) + ' MB'; return (bytes / 1073741824).toFixed(1) + ' GB'; }

async function translateText(text, targetLang) { if (!text.trim()) return ''; try { const res = await fetch('https://api.mymemory.translated.net/get?q=' + encodeURIComponent(text.slice(0, 500)) + '&langpair=fr|' + targetLang); const data = await res.json(); return data.responseData?.translatedText || text; } catch { return text; } }

function wireDocManagerEvents() {
  const form = document.getElementById('doc-form');
  const titleFr = document.getElementById('doc-form-title-fr');
  const titleAr = document.getElementById('doc-form-title-ar');
  const titleEn = document.getElementById('doc-form-title-en');
  titleAutoFill = true; titleTimer = null;
  function isAutoTranslateOn() { var cb = document.getElementById('auto-translate-toggle'); return cb && cb.checked; }
  titleFr.addEventListener('input', () => { if (!titleAutoFill || !isAutoTranslateOn()) return; clearTimeout(titleTimer); const val = titleFr.value; if (!val) { titleAr.value = ''; titleEn.value = ''; return; } titleTimer = setTimeout(async () => { if (titleAr.value === '' || titleAr.dataset.autofilled === 'true') { titleAr.dataset.autofilled = 'true'; titleAr.placeholder = '...'; titleAr.value = await translateText(val, 'ar'); if (titleAr.dataset.autofilled === 'true') titleAr.placeholder = ''; } if (titleEn.value === '' || titleEn.dataset.autofilled === 'true') { titleEn.dataset.autofilled = 'true'; titleEn.placeholder = '...'; titleEn.value = await translateText(val, 'en'); if (titleEn.dataset.autofilled === 'true') titleEn.placeholder = ''; } }, 600); });
  titleAr.addEventListener('input', () => { titleAr.dataset.autofilled = 'false'; titleAutoFill = false; });
  titleEn.addEventListener('input', () => { titleEn.dataset.autofilled = 'false'; titleAutoFill = false; });
  const descFr = document.getElementById('doc-form-desc-fr');
  const descAr = document.getElementById('doc-form-desc-ar');
  const descEn = document.getElementById('doc-form-desc-en');
  descAutoFill = true; descTimer = null;
  descFr.addEventListener('input', () => { if (!descAutoFill || !isAutoTranslateOn()) return; clearTimeout(descTimer); const val = descFr.value; if (!val) { descAr.value = ''; descEn.value = ''; return; } descTimer = setTimeout(async () => { if (descAr.value === '' || descAr.dataset.autofilled === 'true') { descAr.dataset.autofilled = 'true'; descAr.placeholder = '...'; descAr.value = await translateText(val, 'ar'); if (descAr.dataset.autofilled === 'true') descAr.placeholder = ''; } if (descEn.value === '' || descEn.dataset.autofilled === 'true') { descEn.dataset.autofilled = 'true'; descEn.placeholder = '...'; descEn.value = await translateText(val, 'en'); if (descEn.dataset.autofilled === 'true') descEn.placeholder = ''; } }, 600); });
  descAr.addEventListener('input', () => { descAr.dataset.autofilled = 'false'; descAutoFill = false; });
  descEn.addEventListener('input', () => { descEn.dataset.autofilled = 'false'; descAutoFill = false; });
  const previewUrl = document.getElementById('doc-form-preview-url');
  const downloadUrl = document.getElementById('doc-form-download-url');
  const sizeField = document.getElementById('doc-form-size');
  const pagesField = document.getElementById('doc-form-pages');
  async function tryAutoFetchFromUrl(url) { if (!url) return; if (!sizeField.value) { const size = await tryFetchFileSize(url); if (size) sizeField.value = size; } if (!pagesField.value) { const pages = await tryFetchPageCount(url); if (pages) pagesField.value = pages; } }
  [previewUrl, downloadUrl].forEach(field => { if (!field) return; field.addEventListener('paste', () => { setTimeout(() => tryAutoFetchFromUrl(field.value.trim()), 100); }); field.addEventListener('input', () => { if (field.value.trim()) setTimeout(() => tryAutoFetchFromUrl(field.value.trim()), 300); }); });
  document.querySelectorAll('#doc-form input, #doc-form textarea').forEach(el => { el.addEventListener('keydown', (e) => { if (e.key === 'Tab' && !el.value && el.placeholder) el.value = el.placeholder; }); });
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    const tFr = document.getElementById('doc-form-title-fr').value.trim();
    const tAr = document.getElementById('doc-form-title-ar').value.trim();
    const tEn = document.getElementById('doc-form-title-en').value.trim();
    const pUrl = document.getElementById('doc-form-preview-url').value.trim();
    const dUrl = document.getElementById('doc-form-download-url').value.trim();
    if (!tFr || !pUrl || !dUrl) { showToast(t('admin.requiredFieldsMissing')); return; }
    const id = editingDocId || nextDocId(APP.db.documents);
    const existing = editingDocId ? APP.db.documents.find(d => d.id === editingDocId) : null;
    const existingPending = editingDocId && !existing ? getPendingDocs().find(d => d.id === editingDocId) : null;
    const doc = { id, title: { fr: tFr, ar: tAr || tFr, en: tEn || tFr }, level: document.getElementById('doc-form-level').value, stream: document.getElementById('doc-form-stream').value || null, subject: document.getElementById('doc-form-subject').value, type: document.getElementById('doc-form-type').value, year: parseInt(document.getElementById('doc-form-year').value, 10) || new Date().getFullYear(), trimestre: document.getElementById('doc-form-trimestre').value || null, wilaya: document.getElementById('doc-form-wilaya').value.trim() || null, description: { fr: document.getElementById('doc-form-desc-fr').value.trim(), ar: document.getElementById('doc-form-desc-ar').value.trim(), en: document.getElementById('doc-form-desc-en').value.trim() }, fileType: 'pdf', pages: parseInt(document.getElementById('doc-form-pages').value, 10) || 1, size: document.getElementById('doc-form-size').value.trim() || '—', previewUrl: pUrl, downloadUrl: dUrl, host: document.getElementById('doc-form-host').value, source: document.getElementById('doc-form-source').value.trim() || existing?.source || existingPending?.source || '', urlSource: document.getElementById('doc-form-url-source').value.trim() || existing?.urlSource || existingPending?.urlSource || '', urlPdf: document.getElementById('doc-form-url-pdf').value.trim() || existing?.urlPdf || existingPending?.urlPdf || '', downloads: existing?.downloads || existingPending?.downloads || 0, rating: existing?.rating || existingPending?.rating || 0, tags: existing?.tags || existingPending?.tags || [] };
    if (editingIsPending) { const pending = getPendingDocs(); const idx = pending.findIndex(d => d.id === id); if (idx >= 0) pending[idx] = doc; else pending.push(doc); savePendingDocs(pending); } else { upsertLocalDoc(doc); applyLocalDocOverrides(); }
    renderAdminDocTable(); resetDocForm(); showToast(editingDocId ? t('admin.docUpdated') : t('admin.docAdded'));
  });
  document.getElementById('doc-form-cancel-btn').addEventListener('click', resetDocForm);
  const searchInput = document.getElementById('admin-doc-search');
  if (searchInput) searchInput.addEventListener('input', debounce(renderAdminDocTable, 200));
  document.getElementById('export-db-btn').addEventListener('click', exportDbJson);
  const spellCheckBtn = document.getElementById('spell-check-btn');
  if (spellCheckBtn) { spellCheckBtn.addEventListener('click', async () => { const frText = document.getElementById('doc-form-desc-fr').value.trim(); if (!frText) { showToast('Remplis d\'abord la description en français.'); return; } const key = typeof getSelectedKey === 'function' ? getSelectedKey() : null; if (!key) { showToast('Configure une clé API dans l\'onglet IA.'); return; } spellCheckBtn.textContent = '⏳ Correction…'; spellCheckBtn.disabled = true; try { const corrected = await correctTextWithAI(frText, key); if (corrected && corrected !== frText) { document.getElementById('doc-form-desc-fr').value = corrected; document.getElementById('doc-form-desc-fr').dispatchEvent(new Event('input', { bubbles: true })); showToast('Description corrigée !'); } else { showToast('Aucune correction nécessaire.'); } } catch (err) { showToast('Erreur: ' + err.message); } spellCheckBtn.textContent = t('admin.spellCheck') || 'Corriger l\'orthographe'; spellCheckBtn.disabled = false; }); }
}

async function correctTextWithAI(text, keyConfig) {
  const apiKey = (typeof sanitizeApiKey === 'function') ? sanitizeApiKey(keyConfig.apiKey) : keyConfig.apiKey.trim();
  const prompt = 'Corrige les fautes d\'orthographe et de grammaire du texte suivant en français. Ne change PAS le contenu, corrige UNIQUEMENT les erreurs. Réponds UNIQUEMENT avec le texte corrigé.\n\n' + text.slice(0, 1000);
  if (keyConfig.provider === 'openai') { const res = await fetch('https://api.openai.com/v1/chat/completions', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey }, body: JSON.stringify({ model: keyConfig.model || 'gpt-4.1', messages: [{ role: 'user', content: prompt }], max_tokens: 500 }) }); if (!res.ok) throw new Error('HTTP ' + res.status); const data = await res.json(); return data.choices?.[0]?.message?.content?.trim() || text; }
  if (keyConfig.provider === 'anthropic') { const res = await fetch('https://api.anthropic.com/v1/messages', { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' }, body: JSON.stringify({ model: keyConfig.model, max_tokens: 500, messages: [{ role: 'user', content: prompt }] }) }); if (!res.ok) throw new Error('HTTP ' + res.status); const data = await res.json(); return (data.content || []).filter(b => b.type === 'text').map(b => b.text).join('\n').trim() || text; }
  if (keyConfig.provider === 'google') { const res = await fetch('https://generativelanguage.googleapis.com/v1beta/models/' + keyConfig.model + ':generateContent?key=' + apiKey, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ contents: [{ role: 'user', parts: [{ text: prompt }] }] }) }); if (!res.ok) throw new Error('HTTP ' + res.status); const data = await res.json(); return data.candidates?.[0]?.content?.parts?.map(p => p.text).join('\n').trim() || text; }
  throw new Error('Fournisseur non supporté');
}

async function exportDbJson() {
  try { const exportObj = await buildExportObj(); const blob = new Blob([JSON.stringify(exportObj, null, 2)], { type: 'application/json' }); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = 'db.json'; document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url); saveDbBackup('db.json', exportObj); renderDbBackupList(); showToast(t('admin.exported')); } catch (err) { showToast('Erreur export: ' + err.message); }
}
/* ---- PAT Encryption (AES-GCM) ---- */
var GH_PAT_KEY_STORAGE = 'inry_gh_pat_key';

function getOrCreatePatKey() {
  var stored = localStorage.getItem(GH_PAT_KEY_STORAGE);
  if (stored) return stored;
  var arr = new Uint8Array(32);
  crypto.getRandomValues(arr);
  var key = btoa(String.fromCharCode.apply(null, arr));
  localStorage.setItem(GH_PAT_KEY_STORAGE, key);
  return key;
}

async function encryptPat(pat) {
  if (!pat) return null;
  try {
    var keyB64 = getOrCreatePatKey();
    var keyBytes = Uint8Array.from(atob(keyB64), c => c.charCodeAt(0));
    var cryptoKey = await crypto.subtle.importKey('raw', keyBytes, 'AES-GCM', false, ['encrypt']);
    var iv = new Uint8Array(12);
    crypto.getRandomValues(iv);
    var encoded = new TextEncoder().encode(pat);
    var encrypted = await crypto.subtle.encrypt({ name: 'AES-GCM', iv: iv }, cryptoKey, encoded);
    return { iv: btoa(String.fromCharCode.apply(null, iv)), data: btoa(String.fromCharCode.apply(null, new Uint8Array(encrypted))) };
  } catch(e) { console.error('PAT encrypt error:', e); return null; }
}

async function decryptPat(encryptedObj) {
  if (!encryptedObj || !encryptedObj.iv || !encryptedObj.data) return '';
  try {
    var keyB64 = localStorage.getItem(GH_PAT_KEY_STORAGE);
    if (!keyB64) return '';
    var keyBytes = Uint8Array.from(atob(keyB64), c => c.charCodeAt(0));
    var cryptoKey = await crypto.subtle.importKey('raw', keyBytes, 'AES-GCM', false, ['decrypt']);
    var iv = Uint8Array.from(atob(encryptedObj.iv), c => c.charCodeAt(0));
    var data = Uint8Array.from(atob(encryptedObj.data), c => c.charCodeAt(0));
    var decrypted = await crypto.subtle.decrypt({ name: 'AES-GCM', iv: iv }, cryptoKey, data);
    return new TextDecoder().decode(decrypted);
  } catch(e) { console.error('PAT decrypt error:', e); return ''; }
}

function buildExportObj() { var ghCfg = getGithubConfig(); var patPromise = encryptPat(ghCfg.pat); var result = { meta: APP.db.meta, levels: APP.db.levels, streams: APP.db.streams, subjects: APP.db.subjects, documentTypes: APP.db.documentTypes, wilayas: APP.db.wilayas, institutions: APP.db.institutions, hosts: APP.db.hosts, documents: APP.db.documents, hidden: { docIds: getHiddenIds(), levelIds: getEntityHiddenIds('levels'), streamIds: getEntityHiddenIds('streams'), subjectIds: getEntityHiddenIds('subjects') }, githubSync: { encryptedPAT: null, patKey: localStorage.getItem(GH_PAT_KEY_STORAGE) || '', repo: ghCfg.repo || '', branch: ghCfg.branch || 'main', path: ghCfg.path || 'repo/data/db.json', autoPush: getGithubAutoPush() } }; return patPromise.then(function(enc) { if (enc) result.githubSync.encryptedPAT = enc; return result; }); }

const DB_BACKUPS_KEY = 'inry_db_backups';
const MAX_BACKUPS = 5;
function computeDbStats(data) { var docs = data.documents || []; var total = docs.length; var subjects = {}; var types = {}; var years = {}; docs.forEach(function(d) { var s = APP.db.subjects.find(function(s) { return s.id === d.subject; }); var sn = s ? (localized(s.name) || d.subject) : d.subject; subjects[sn] = (subjects[sn] || 0) + 1; var tp = APP.db.documentTypes.find(function(t) { return t.id === d.type; }); var tn = tp ? (localized(tp.name) || d.type) : d.type; types[tn] = (types[tn] || 0) + 1; if (d.year) years[d.year] = (years[d.year] || 0) + 1; }); return { total: total, subjects: subjects, types: types, years: Object.keys(years).sort() }; }
function getDbBackups() { try { return JSON.parse(localStorage.getItem(DB_BACKUPS_KEY)) || []; } catch(e) { return []; } }
function saveDbBackup(name, data) { var json = JSON.stringify(data); var sizeBytes = new Blob([json]).size; var sizeLabel = sizeBytes < 1024 ? sizeBytes + ' o' : sizeBytes < 1048576 ? (sizeBytes / 1024).toFixed(1) + ' Ko' : (sizeBytes / 1048576).toFixed(1) + ' Mo'; var stats = computeDbStats(data); var backups = getDbBackups(); backups.unshift({ id: Date.now(), name: name || 'db.json', timestamp: new Date().toISOString(), size: sizeLabel, stats: stats, data: data }); if (backups.length > MAX_BACKUPS) backups = backups.slice(0, MAX_BACKUPS); try { localStorage.setItem(DB_BACKUPS_KEY, JSON.stringify(backups)); } catch(e) { showToast('Stockage local saturé'); } }
function deleteDbBackup(id) { localStorage.setItem(DB_BACKUPS_KEY, JSON.stringify(getDbBackups().filter(function(b) { return b.id !== id; }))); }
function renderDbBackupList() {
  var el = document.getElementById('db-backup-list'); if (!el) return;
  var backups = getDbBackups();
  if (!backups.length) { el.innerHTML = '<div style="padding:var(--space-3);font-size:var(--fs-xs);color:var(--ink-soft);text-align:center;">Aucune sauvegarde locale</div>'; return; }
  el.innerHTML = backups.map(function(b) { var s = b.stats || {}; var tip = []; tip.push('📄 ' + s.total + ' document' + (s.total > 1 ? 's' : '')); if (b.size) tip.push('💾 ' + b.size); if (s.years && s.years.length) tip.push('📅 ' + s.years[0] + (s.years.length > 1 ? '–' + s.years[s.years.length - 1] : '')); return '<div class="db-backup-item" style="display:flex;align-items:center;gap:var(--space-2);padding:var(--space-2);border:1px solid var(--kraft-line);border-radius:var(--radius-sm);margin-bottom:var(--space-1);"><div class="db-backup-tooltip" data-tt="' + escapeHTML(tip.join('<br>')) + '">' + tip.join('<br>') + '</div><span style="flex:1;font-size:var(--fs-xs);"><strong>' + escapeHTML(b.name || 'db.json') + '</strong>' + (b.size ? ' <span style="color:var(--ink-soft);font-size:9px;">(' + escapeHTML(b.size) + ')</span>' : '') + '<br><span style="color:var(--ink-soft);font-size:10px;">' + new Date(b.timestamp).toLocaleString() + '</span></span><button class="btn btn-primary btn-sm db-backup-restore-btn" data-backup-id="' + b.id + '">Restaurer</button><button class="btn btn-ghost btn-sm db-backup-del-btn" data-backup-id="' + b.id + '">✕</button></div>'; }).join('');
  el.querySelectorAll('.db-backup-restore-btn').forEach(function(btn) { btn.addEventListener('click', function() { var backup = getDbBackups().find(function(b) { return b.id === parseInt(btn.dataset.backupId); }); if (!backup) return; if (!confirm('Restaurer "' + (backup.name || 'db.json') + '" ?')) return; importDbData(backup.data); }); });
  el.querySelectorAll('.db-backup-del-btn').forEach(function(btn) { btn.addEventListener('click', function() { deleteDbBackup(parseInt(btn.dataset.backupId)); renderDbBackupList(); }); });
  el.querySelectorAll('.db-backup-item').forEach(function(item) { var tip = item.querySelector('.db-backup-tooltip'); if (!tip) return; function showTip(e) { var rect = item.getBoundingClientRect(); tip.classList.add('show'); tip.style.left = Math.min(rect.left, window.innerWidth - 320) + 'px'; var spaceBelow = window.innerHeight - rect.bottom; if (spaceBelow >= 132) { tip.style.top = (rect.bottom + 8) + 'px'; tip.style.bottom = 'auto'; } else { tip.style.top = 'auto'; tip.style.bottom = (window.innerHeight - rect.top + 8) + 'px'; } } item.addEventListener('mouseenter', showTip); item.addEventListener('mousemove', showTip); item.addEventListener('mouseleave', function() { tip.classList.remove('show'); }); });
}

function importDbData(data) { try { if (!data || !data.meta || !data.documents) { showToast('Fichier invalide'); return; } localStorage.setItem('inry_custom_db', JSON.stringify(data)); localStorage.removeItem('inry_local_docs'); localStorage.removeItem('inry_deleted_ids'); showToast('Base importée ! Rechargement…'); setTimeout(function() { location.reload(); }, 800); } catch(err) { showToast('Erreur: ' + err.message); } }

var autoBackupTimer = null;
var AUTO_BACKUP_KEY = 'inry_auto_backup';
var AUTO_BACKUP_LAST_KEY = 'inry_auto_backup_last';
var AUTO_BACKUP_CHECK_INTERVAL = 30000;
function getAutoBackupConfig() { try { var raw = localStorage.getItem(AUTO_BACKUP_KEY); if (!raw) return { mode: 'off' }; return JSON.parse(raw); } catch(e) { return { mode: 'off' }; } }
function setAutoBackupConfig(cfg) { try { localStorage.setItem(AUTO_BACKUP_KEY, JSON.stringify(cfg)); } catch(e) {} }
function stopAutoBackup() { if (autoBackupTimer) { clearInterval(autoBackupTimer); autoBackupTimer = null; } }
function getDbDataForBackup() { var custom = localStorage.getItem('inry_custom_db'); if (custom) { try { return JSON.parse(custom); } catch(e) {} } var local = localStorage.getItem('inry_local_docs'); var deleted = localStorage.getItem('inry_deleted_ids'); return { meta: APP.db ? APP.db.meta : { version: 1 }, documents: local ? JSON.parse(local) : (APP.db ? APP.db.documents : []), subjects: APP.db ? APP.db.subjects : [], documentTypes: APP.db ? APP.db.documentTypes : [], studyLevels: APP.db ? APP.db.studyLevels : [], removedIds: deleted ? JSON.parse(deleted) : [] }; }
function shouldRunBackup(cfg) { var now = Date.now(); var last = 0; try { last = parseInt(localStorage.getItem(AUTO_BACKUP_LAST_KEY)) || 0; } catch(e) {} if (cfg.mode === 'interval') { var ms = parseInt(cfg.value) * (cfg.unit === 'minutes' ? 60000 : cfg.unit === 'hours' ? 3600000 : 86400000); if (isNaN(ms) || ms <= 0) return false; return (now - last) >= ms; } if (cfg.mode === 'fixed') { var d = new Date(); var target = new Date(d.getFullYear(), d.getMonth(), d.getDate(), parseInt(cfg.hour) || 0, parseInt(cfg.minute) || 0); if (target <= new Date(last)) return false; return now >= target.getTime(); } return false; }
function performAutoBackup() { var cfg = getAutoBackupConfig(); if (cfg.mode === 'off') return; if (!shouldRunBackup(cfg)) return; try { localStorage.setItem(AUTO_BACKUP_LAST_KEY, String(Date.now())); } catch(e) {} var data = getDbDataForBackup(); if (!data || !data.documents) return; saveDbBackup('auto-' + new Date().toISOString().slice(0,10), data); }
function startAutoBackup() { stopAutoBackup(); var cfg = getAutoBackupConfig(); if (cfg.mode === 'off') return; performAutoBackup(); autoBackupTimer = setInterval(performAutoBackup, AUTO_BACKUP_CHECK_INTERVAL); }
function wireAutoBackupUI() {
  var cfg = getAutoBackupConfig(); var modeRadios = document.querySelectorAll('input[name="auto-backup-mode"]');
  if (!modeRadios.length) return;
  modeRadios.forEach(function(r) { r.checked = r.value === cfg.mode; });
  toggleAutoBackupGroups(cfg.mode);
  modeRadios.forEach(function(r) { r.addEventListener('change', function() { toggleAutoBackupGroups(r.value); }); });
  document.getElementById('auto-backup-interval-val').value = cfg.value || 1;
  document.getElementById('auto-backup-interval-unit').value = cfg.unit || 'hours';
  var h = ('0' + (cfg.hour || 8)).slice(-2); var m = ('0' + (cfg.minute || 0)).slice(-2);
  document.getElementById('auto-backup-fixed-hour').value = h + ':' + m;
  document.getElementById('auto-backup-save').addEventListener('click', function() { var mode = document.querySelector('input[name="auto-backup-mode"]:checked'); if (!mode) return; var newCfg = { mode: mode.value }; if (mode.value === 'interval') { newCfg.value = parseInt(document.getElementById('auto-backup-interval-val').value) || 1; newCfg.unit = document.getElementById('auto-backup-interval-unit').value; } else if (mode.value === 'fixed') { var tp = document.getElementById('auto-backup-fixed-hour').value.split(':'); newCfg.hour = parseInt(tp[0]) || 0; newCfg.minute = parseInt(tp[1]) || 0; } setAutoBackupConfig(newCfg); startAutoBackup(); showToast(mode.value === 'off' ? 'Sauvegarde auto désactivée' : 'Sauvegarde auto activée'); });
}
function toggleAutoBackupGroups(mode) { var ig = document.getElementById('auto-backup-interval-group'); var fg = document.getElementById('auto-backup-fixed-group'); if (ig) ig.style.display = mode === 'interval' ? 'flex' : 'none'; if (fg) fg.style.display = mode === 'fixed' ? 'flex' : 'none'; }
function wireImportBackupUI() {
  document.getElementById('import-db-btn').addEventListener('click', function() { var fi = document.getElementById('import-db-file-input'); var file = fi.files[0]; if (!file) { showToast('Selectionne un fichier db.json.'); return; } var reader = new FileReader(); reader.onload = function(e) { try { importDbData(JSON.parse(e.target.result)); } catch(err) { showToast('Erreur: ' + err.message); } }; reader.readAsText(file); });
  document.getElementById('reset-db-btn').addEventListener('click', function() { if (!confirm('Reinitialiser la base ?')) return; localStorage.removeItem('inry_custom_db'); localStorage.removeItem('inry_local_docs'); localStorage.removeItem('inry_deleted_ids'); localStorage.removeItem('inry_hidden_doc_ids'); showToast('Base reinitialisee. Rechargement...'); setTimeout(function() { location.reload(); }, 800); });
  renderDbBackupList();
}

