    fetch(base + 'data/db.json'),
    fetch(base + 'data/i18n.json')
  ]);
  var defaultDb = await dbRes.json();
  loadHiddenIdsFromDefault(defaultDb);
  var customDb = localStorage.getItem('inry_custom_db');
