const GH_CONFIG_KEY = 'inry_github_sync';
const GH_AUTO_PUSH_KEY = 'inry_github_auto_push';

function getGithubConfig() {
  try {
    var raw = localStorage.getItem(GH_CONFIG_KEY);
    return raw ? JSON.parse(raw) : { pat: '', repo: 'droidapk1002-beep/inry-biblio-assets', branch: 'main', path: 'repo/data/db.json' };
  } catch(e) { return { pat: '', repo: 'droidapk1002-beep/inry-biblio-assets', branch: 'main', path: 'repo/data/db.json' }; }
}

function saveGithubConfig(cfg) {
  try { localStorage.setItem(GH_CONFIG_KEY, JSON.stringify(cfg)); } catch(e) {}
}

function getGithubAutoPush() {
  return localStorage.getItem(GH_AUTO_PUSH_KEY) === 'true';
}

function setGithubAutoPush(val) {
  try { localStorage.setItem(GH_AUTO_PUSH_KEY, val ? 'true' : 'false'); } catch(e) {}
}

function githubLog(msg, isError) {
  var el = document.getElementById('github-push-log');
  var status = document.getElementById('github-push-status');
  if (el) {
    el.style.display = 'block';
    var line = document.createElement('div');
    line.style.color = isError ? 'var(--red-stamp)' : 'var(--ink-soft)';
    line.style.marginBottom = '2px';
    line.textContent = '[' + new Date().toLocaleTimeString() + '] ' + msg;
    el.appendChild(line);
    el.scrollTop = el.scrollHeight;
  }
  if (status) {
    status.textContent = isError ? msg : msg;
    status.style.color = isError ? 'var(--red-stamp)' : 'var(--green)';
  }
}

async function pushDbToGithub() {
  var cfg = getGithubConfig();
  if (!cfg.pat) { showToast('Token GitHub manquant'); githubLog('Token GitHub manquant', true); return; }
  if (!cfg.repo || !cfg.branch || !cfg.path) { showToast('Config GitHub incomplete'); githubLog('Config GitHub incomplete', true); return; }

  var statusEl = document.getElementById('github-push-status');
  if (statusEl) { statusEl.textContent = 'Push en cours...'; statusEl.style.color = 'var(--ink-soft)'; }
  githubLog('Preparation du push...');

  try {
    applyLocalDocOverrides();
    var exportObj = await buildExportObj();
    var content = JSON.stringify(exportObj, null, 2);
    var encodedContent = btoa(unescape(encodeURIComponent(content)));

    var apiUrl = 'https://api.github.com/repos/' + cfg.repo + '/contents/' + cfg.path;
    var headers = { 'Authorization': 'token ' + cfg.pat, 'Accept': 'application/vnd.github.v3+json' };

    var existingSha = null;
    var getRes = await fetch(apiUrl + '?ref=' + cfg.branch, { headers: headers });
    if (getRes.ok) {
      var existing = await getRes.json();
      existingSha = existing.sha;
      githubLog('Fichier existant trouve, SHA: ' + existingSha.substring(0, 8));
    } else if (getRes.status === 404) {
      githubLog('Fichier inexistant, creation...');
    } else {
      var errText = await getRes.text();
      githubLog('Erreur lecture: ' + getRes.status + ' ' + errText, true);
      showToast('Erreur lecture GitHub');
      return;
    }

    var body = { message: 'chore(db): update db.json via inry-biblio admin [' + new Date().toISOString().slice(0, 19) + ']', content: encodedContent, branch: cfg.branch };
    if (existingSha) body.sha = existingSha;

    var putRes = await fetch(apiUrl, { method: 'PUT', headers: headers, body: JSON.stringify(body) });
    if (putRes.ok) {
      var result = await putRes.json();
      githubLog('Push reussi ! Commit: ' + (result.commit && result.commit.sha || '').substring(0, 8));
      showToast('db.json pousse sur GitHub');
      saveDbBackup('github-push', exportObj);
      renderDbBackupList();
    } else {
      var errBody = await putRes.text();
      githubLog('Erreur push: ' + putRes.status + ' ' + errBody, true);
      showToast('Erreur push GitHub');
    }
  } catch(err) {
    githubLog('Erreur reseau: ' + err.message, true);
    showToast('Erreur: ' + err.message);
  }
}

function wireGithubSync() {
  var patInput = document.getElementById('github-pat-input');
  var repoInput = document.getElementById('github-repo-input');
  var branchInput = document.getElementById('github-branch-input');
  var pathInput = document.getElementById('github-path-input');
  var pushBtn = document.getElementById('github-push-btn');
  var saveCfgBtn = document.getElementById('github-save-config-btn');
  var autoPushCheck = document.getElementById('github-auto-push');

  var cfg = getGithubConfig();
  if (patInput) patInput.value = cfg.pat || '';
  if (repoInput) repoInput.value = cfg.repo || '';
  if (branchInput) branchInput.value = cfg.branch || 'main';
  if (pathInput) pathInput.value = cfg.path || 'repo/data/db.json';
  if (autoPushCheck) autoPushCheck.checked = getGithubAutoPush();

  if (saveCfgBtn) {
    saveCfgBtn.addEventListener('click', function() {
      var newCfg = {
        pat: patInput ? patInput.value.trim() : '',
        repo: repoInput ? repoInput.value.trim() : '',
        branch: branchInput ? branchInput.value.trim() : 'main',
        path: pathInput ? pathInput.value.trim() : 'repo/data/db.json'
      };
      saveGithubConfig(newCfg);
      showToast('Config GitHub sauvegardee');
      githubLog('Config sauvegardee');
    });
  }

  if (pushBtn) {
    pushBtn.addEventListener('click', function() {
      var cfg2 = getGithubConfig();
      cfg2.pat = patInput ? patInput.value.trim() : cfg2.pat;
      cfg2.repo = repoInput ? repoInput.value.trim() : cfg2.repo;
      cfg2.branch = branchInput ? branchInput.value.trim() : cfg2.branch;
      cfg2.path = pathInput ? pathInput.value.trim() : cfg2.path;
      saveGithubConfig(cfg2);
      pushDbToGithub();
    });
  }

  if (autoPushCheck) {
    autoPushCheck.addEventListener('change', function() {
      setGithubAutoPush(autoPushCheck.checked);
      showToast(autoPushCheck.checked ? 'Auto-push active' : 'Auto-push desactive');
    });
  }
}

var _autoPushTimer = null;
function scheduleAutoPush() {
  if (!getGithubAutoPush()) return;
  if (_autoPushTimer) clearTimeout(_autoPushTimer);
  _autoPushTimer = setTimeout(function() {
    var cfg = getGithubConfig();
    if (cfg.pat) pushDbToGithub();
  }, 2000);
}

function guessLevel(raw) { const map = { '1am': 'm1','2am': 'm2','3am': 'm3','4am': 'm4','1as': 's1','2as': 's2','3as': 's3','ap1': 'p1','ap2': 'p2','ap3': 'p3','ap4': 'p4','ap5': 'p5' }; return map[raw] || raw; }
function guessSubject(raw, db) { const sub = (db.subjects || []).find(s => raw.includes(s.id) || raw.includes(localized(s.name).toLowerCase())); return sub ? sub.id : raw; }
function guessType(raw, db) { const map = { devoir: 'devoir', composition: 'devoir', examen: 'examen', fiche: 'fiche', cours: 'cours', serie: 'serie', exercice: 'exercice', sujet: 'bac-bem', bac: 'bac-bem', bem: 'bac-bem', corrige: 'corrige', correction: 'corrige' }; if (raw && typeof raw === 'string') { const lc = raw.toLowerCase(); for (const [k, v] of Object.entries(map)) { if (lc.includes(k)) return v; } } return raw || 'devoir'; }
function guessStream(raw, db) { const map = { science: 'sci', maths: 'math', technique: 'tech', lettre: 'lettres', gestion: 'eco', economie: 'eco', langues: 'langues', philo: 'philo' }; if (raw && typeof raw === 'string') { const lc = raw.toLowerCase(); for (const [k, v] of Object.entries(map)) { if (lc.includes(k)) return v; } } return raw || null; }
function guessTrimestre(raw) { const map = { '1': 't1', '2': 't2', '3': 't3', '01': 't1', '02': 't2', '03': 't3', premier: 't1', deuxieme: 't2', troisieme: 't3', '1er': 't1', '2eme': 't2', '3eme': 't3' }; if (raw && typeof raw === 'string') { const lc = raw.toLowerCase().trim(); if (map[lc]) return map[lc]; if (lc.includes('1')) return 't1'; if (lc.includes('2')) return 't2'; if (lc.includes('3')) return 't3'; } return raw || null; }
function extractDriveId(url) { if (!url) return ''; const m = url.match(/[?&]id=([^&]+)/) || url.match(/\/d\/([^/?#&]+)/) || url.match(/\/file\/d\/([^/?#&]+)/); return m ? m[1] : ''; }
function toDrivePreview(id) { return id ? 'https://drive.google.com/file/d/' + id + '/preview' : ''; }
function toDriveDownload(id) { return id ? 'https://drive.google.com/uc?export=download&id=' + id : ''; }
function stripEmoji(str) { return str.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{2702}\u{2795}\u{2796}\u{274C}\u{274E}\u{2757}\u{203C}\u{2049}\u{2139}\u{24C2}\u{2934}\u{2935}\u{2B05}\u{2B06}\u{2B07}\u{2B1B}\u{2B1C}\u{2B50}\u{2B55}\u{3030}\u{303D}\u{3297}\u{3299}]/gu, '').trim(); }
async function translateFromAr(text, targetLang) { if (!text.trim()) return ''; const cleaned = stripEmoji(text); try { const res = await fetch('https://api.mymemory.translated.net/get?q=' + encodeURIComponent(cleaned.slice(0, 500)) + '&langpair=ar|' + targetLang); const data = await res.json(); return data.responseData?.translatedText || cleaned; } catch { return cleaned; } }
function detectProviderFromUrl(url) { if (!url) return null; if (url.includes('mega.nz')) return 'mega'; if (url.includes('drive.google.com')) return 'google'; if (url.includes('dropbox.com')) return 'dropbox'; if (url.includes('sharepoint.com') || url.includes('onedrive.live.com')) return 'onedrive'; return null; }
function migrateHostFromUrl() { const pending = getPendingDocs(); const localDocs = getLocalDocs(); let updated = 0; pending.forEach(d => { const provider = detectProviderFromUrl(d.previewUrl) || detectProviderFromUrl(d.downloadUrl); if (provider && d.host !== provider) { d.host = provider; updated++; } }); savePendingDocs(pending); localDocs.forEach(d => { const provider = detectProviderFromUrl(d.previewUrl) || detectProviderFromUrl(d.downloadUrl); if (provider && d.host !== provider) { d.host = provider; updated++; } }); saveLocalDocs(localDocs); applyLocalDocOverrides(); renderAdminDocTable(); showToast(updated + ' document(s) mis à jour'); }
async function batchAddAll(parsedDocs, rawDocs) { let idCounter = Math.max(0, ...APP.db.documents.map(d => parseInt((d.id||'').replace('doc-',''),10)).filter(n=>!isNaN(n)), ...getPendingDocs().map(d => parseInt((d.id||'').replace('doc-',''),10)).filter(n=>!isNaN(n))); const pending = getPendingDocs(); let count = 0; for (let i = 0; i < parsedDocs.length; i++) { const d = parsedDocs[i]; const [frTitle, enTitle] = await Promise.all([d.title.fr || translateFromAr(d.title.ar, 'fr'), d.title.en || translateFromAr(d.title.ar, 'en')]); idCounter++; pending.push({ id: 'doc-' + String(idCounter).padStart(4, '0'), title: { fr: frTitle, ar: d.title.ar, en: enTitle }, level: d.level, stream: d.stream || null, subject: d.subject, type: d.type, year: d.year, trimestre: d.trimestre || null, wilaya: d.wilaya, description: { fr: frTitle, ar: d.title.ar, en: enTitle }, fileType: 'pdf', pages: d.pages, size: d.size, previewUrl: d.previewUrl, downloadUrl: d.downloadUrl, host: d.host, source: d.source || '', urlSource: d.urlSource || '', urlPdf: d.urlPdf || '', downloads: 0, rating: 0, tags: [] }); count++; } savePendingDocs(pending); renderAdminDocTable(); showToast(count + ' document(s) importé(s) — en attente de validation'); }
function openAdminPdfPreview(url) { const overlay = document.createElement('div'); overlay.className = 'pdf-preview-overlay'; overlay.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;'; overlay.addEventListener('click', e => { if (e.target === overlay) close(); }); const box = document.createElement('div'); box.style.cssText = 'position:relative;width:90vw;height:90vh;background:#fff;border-radius:8px;overflow:hidden;display:flex;flex-direction:column;'; const header = document.createElement('div'); header.style.cssText = 'display:flex;align-items:center;justify-content:space-between;padding:8px 12px;background:#f5f5f5;border-bottom:1px solid #ddd;'; const title = document.createElement('span'); title.textContent = '📄 Aperçu PDF'; title.style.cssText = 'font-weight:600;'; const closeBtn = document.createElement('button'); closeBtn.textContent = '✕'; closeBtn.style.cssText = 'background:none;border:none;font-size:18px;cursor:pointer;padding:0 4px;'; closeBtn.addEventListener('click', close); header.appendChild(title); header.appendChild(closeBtn); const iframe = document.createElement('iframe'); iframe.src = url; iframe.style.cssText = 'flex:1;border:none;width:100%;'; iframe.allow = 'fullscreen'; box.appendChild(header); box.appendChild(iframe); overlay.appendChild(box); document.body.appendChild(overlay); function close() { overlay.remove(); document.removeEventListener('keydown', keyHandler); } function keyHandler(e) { if (e.key === 'Escape') close(); } document.addEventListener('keydown', keyHandler); }

if (typeof escapeHTML !== 'function' || !escapeHTML(42)) {
  window.escapeHTML = function(s) {
    var d = document.createElement('div');
    d.appendChild(document.createTextNode(String(s)));
    return d.innerHTML;
  };
}
