function homeRender() {
  document.title = t('siteName') + ' — ' + t('tagline');

  var hiddenDocIds = new Set((function() { try { return JSON.parse(localStorage.getItem('inry_hidden_doc_ids') || '[]'); } catch(e) { return []; } })());
  var visibleDocs = APP.db.documents.filter(function(d) { return !hiddenDocIds.has(d.id); });
  document.getElementById('stat-docs').textContent = visibleDocs.length + '+';
  document.getElementById('stat-subjects').textContent = APP.db.subjects.length;
  document.getElementById('stat-levels').textContent = 4;

  document.getElementById('hero-stamp').textContent = '🇩🇿 ' + t('siteName');

  var levelsGrid = document.getElementById('levels-grid');
  var levelCategories = [
    { id: 'prescolaire', name: { fr: 'Préscolaire', ar: 'تحضيري', en: 'Preschool' }, levelIds: ['presco'] },
    { id: 'primaire', name: { fr: 'Primaire', ar: 'ابتدائي', en: 'Primary' }, levelIds: ['p1','p2','p3','p4','p5'] },
    { id: 'moyen', name: { fr: 'Moyen', ar: 'متوسط', en: 'Middle School' }, levelIds: ['m1','m2','m3','m4'] },
    { id: 'lycee', name: { fr: 'Lycée', ar: 'ثانوي', en: 'High School' }, levelIds: ['s1','s2','s3'] }
  ];
  levelsGrid.innerHTML = levelCategories.map(function(cat) {
    var count = APP.db.documents.filter(function(d) { return cat.levelIds.indexOf(d.level) >= 0 && !hiddenDocIds.has(d.id); }).length;
    var years = APP.db.levels.flatMap(function(g) { return g.years; }).filter(function(y) { return cat.levelIds.indexOf(y.id) >= 0; });
    return '<div class="level-category">' +
      '<a class="quick-tile" href="javascript:void(0)" onclick="toggleLevelCategory(\'' + cat.id + '\')" data-cat="' + cat.id + '">' +
        '<div class="quick-tile-icon">' + icon('book') + '</div>' +
        '<div>' +
          '<div class="quick-tile-name">' + escapeHTML(localized(cat.name)) + '</div>' +
          '<div class="quick-tile-count">' + count + ' ' + t('filters.results') + '</div>' +
        '</div>' +
        '<span class="expand-icon">' + icon('chevronDown') + '</span>' +
      '</a>' +
      '<div class="level-subgrid" id="subgrid-' + cat.id + '" style="display:none;">' +
        years.map(function(year) {
          var yCount = APP.db.documents.filter(function(d) { return d.level === year.id && !hiddenDocIds.has(d.id); }).length;
          return '<a class="quick-tile sub-tile" href="#library?level=' + year.id + '">' +
            '<div class="quick-tile-icon">' + icon('fileText') + '</div>' +
            '<div>' +
              '<div class="quick-tile-name">' + escapeHTML(localized(year.name)) + '</div>' +
              '<div class="quick-tile-count">' + yCount + ' ' + t('filters.results') + '</div>' +
            '</div>' +
          '</a>';
        }).join('') +
      '</div>' +
    '</div>';
  }).join('');

  var subjectsGrid = document.getElementById('subjects-grid');
  subjectsGrid.innerHTML = APP.db.subjects.map(function(sub) {
    var count = APP.db.documents.filter(function(d) { return d.subject === sub.id && !hiddenDocIds.has(d.id); }).length;
    return '<a class="quick-tile" href="#library?subject=' + sub.id + '">' +
      '<div class="quick-tile-icon" style="color:' + sub.color + '; background:' + sub.color + '1a;">' + icon(sub.icon) + '</div>' +
      '<div>' +
        '<div class="quick-tile-name">' + escapeHTML(localized(sub.name)) + '</div>' +
        '<div class="quick-tile-count">' + count + ' ' + t('filters.results') + '</div>' +
      '</div>' +
    '</a>';
  }).join('');

  var featured = APP.db.documents
    .filter(function(d) { return d.type === 'bac-bem' && !hiddenDocIds.has(d.id); })
    .sort(function(a, b) { return b.downloads - a.downloads; })
    .slice(0, 6);
  renderDocGrid('featured-grid', featured);

  wireLayoutEvents();

  document.getElementById('hero-search-form').addEventListener('submit', function(e) {
    e.preventDefault();
    var q = document.getElementById('hero-search-input').value.trim();
    window.location.hash = 'library' + (q ? '?q=' + encodeURIComponent(q) : '');
  });
}

function toggleLevelCategory(catId) {
  var subgrid = document.getElementById('subgrid-' + catId);
  if (!subgrid) return;
  var isHidden = subgrid.style.display === 'none' || !subgrid.style.display;
  subgrid.style.display = isHidden ? 'grid' : 'none';
  var tile = document.querySelector('[data-cat="' + catId + '"]');
  if (tile) tile.classList.toggle('expanded', isHidden);
}

function applyURLParamsToFilters() {
  var hash = window.location.hash || '';
  var qIdx = hash.indexOf('?');
  if (qIdx < 0) return;
  var params = new URLSearchParams(hash.substring(qIdx));
  ['level', 'levelGroup', 'stream', 'subject', 'type', 'trimestre', 'year'].forEach(function(key) {
    if (params.has(key)) APP.filters[key] = params.get(key);
  });
  if (params.has('q')) APP.filters.search = params.get('q');
}

function libraryRender() {
  var docs = getFilteredDocs();
  renderDocGrid('library-grid', docs);
  document.getElementById('filters-count').textContent = docs.length + ' ' + t('filters.results');
}

function initLibraryPage() {
  document.title = t('nav.library') + ' — ' + t('siteName');
  applyURLParamsToFilters();
  populateFilterBar();
  wireFilterBar(libraryRender);
  wireLayoutEvents();
  libraryRender();

  var sf = document.getElementById('search-form');
  if (sf) sf.addEventListener('submit', function(e) { e.preventDefault(); });
}

/* ============================================================
   INRY-BIBLIO — Routeur mono-page pour Blogger
   Affiche l'une des 4 "vues" (home/library/assistant/admin) en
   fonction du hash de l'URL (#home, #library, #assistant, #admin),
   sans jamais recharger la page.
   ============================================================ */

function fpCurrentView() {
  var h = (window.location.hash || '').replace(/^#\/?/, '').split(/[/?]/)[0];
  if (h === 'library' || h === 'assistant' || h === 'admin') return h;
  return 'home';
}

function fpRoute() {
  var view = fpCurrentView();
  ['home', 'library', 'assistant', 'admin'].forEach(function(v) {
    var el = document.getElementById('fp-view-' + v);
    if (el) el.style.display = (v === view) ? '' : 'none';
  });

  document.title = (view === 'assistant' ? t('assistant.title') + ' — ' : '') + t('siteName') + (view === 'home' ? ' — ' + t('tagline') : '');
  document.getElementById('header-root').innerHTML = renderHeader(view);
  document.getElementById('footer-root').innerHTML = renderFooter();
  translateStaticDOM();
  wireLayoutEvents();
  var themeToggle = document.getElementById('theme-toggle');
  if (themeToggle) {
    themeToggle.innerHTML = icon(APP.theme === 'light' ? 'moon' : 'sun');
    themeToggle.onclick = function() {
      toggleTheme();
      themeToggle.innerHTML = icon(APP.theme === 'light' ? 'moon' : 'sun');
    };
  }
  window.scrollTo(0, 0);

  try {
    if (view === 'home') homeRender();
    else if (view === 'library') initLibraryPage();
    else if (view === 'assistant') initAssistantPage();
    else if (view === 'admin') {
      initAdminPage();
      wireAdminTabs();
      var lockIcon = document.getElementById('lock-icon');
      if (lockIcon) lockIcon.innerHTML = icon('lock');
      var settingsIcon = document.getElementById('settings-icon');
      if (settingsIcon) settingsIcon.innerHTML = icon('settings');
      var passwordIcon = document.getElementById('password-icon');
      if (passwordIcon) passwordIcon.innerHTML = icon('lock');
      var docFormIcon = document.getElementById('doc-form-icon');
      if (docFormIcon) docFormIcon.innerHTML = icon('fileText');
      var exportIcon = document.getElementById('export-icon');
      if (exportIcon) exportIcon.innerHTML = icon('download');
      var exportBtnIcon = document.getElementById('export-btn-icon');
      if (exportBtnIcon) exportBtnIcon.innerHTML = icon('download');
      var importIcon = document.getElementById('import-icon');
      if (importIcon) importIcon.innerHTML = icon('upload');
    }
  } catch (e) {
    console.error('[fpRoute:' + view + ']', e);
  }
}

/* ============================================================
   Admin tabs wiring + import helpers
   ============================================================ */
function wireAdminTabs() {
  document.querySelectorAll('.admin-tab-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      document.querySelectorAll('.admin-tab-btn').forEach(function(b) { b.classList.remove('active'); });
      btn.classList.add('active');
      document.getElementById('tab-panel-docs').classList.toggle('hidden', btn.dataset.tab !== 'docs');
      document.getElementById('tab-panel-keys').classList.toggle('hidden', btn.dataset.tab !== 'keys');
      document.getElementById('tab-panel-password').classList.toggle('hidden', btn.dataset.tab !== 'password');
    });
  });
  document.querySelectorAll('.admin-sub-tab').forEach(function(btn) {
    btn.addEventListener('click', function() {
      document.querySelectorAll('.admin-sub-tab').forEach(function(b) { b.classList.remove('active'); });
      btn.classList.add('active');
      document.querySelectorAll('#tab-panel-docs .admin-sub-panel').forEach(function(p) { p.classList.add('hidden'); });
      document.getElementById('sub-panel-' + btn.dataset.subtab).classList.remove('hidden');
    });
  });
  var importAnalyzeBtn = document.getElementById('import-analyze-btn');
  var importInput = document.getElementById('import-manifest-input');
  if (importAnalyzeBtn && importInput) {
    importAnalyzeBtn.addEventListener('click', function() {
      var file = importInput.files[0];
      if (!file) { showToast('Sélectionne un fichier JSON d\'abord.'); return; }
      var reader = new FileReader();
      reader.onload = function(e) {
        try {
          var raw = JSON.parse(e.target.result);
          var items = raw.items || raw.documents || raw.fichiers || raw.data || (Array.isArray(raw) ? raw : [raw]);
          if (!items.length) { showToast('Aucun document trouvé dans le fichier.'); return; }
          var normalized = items.map(normalizeImportItem);
          renderImportPreview(normalized, items);
        } catch(err) { showToast('Erreur de lecture: ' + err.message); }
      };
      reader.readAsText(file);
    });
  }
  var migrateBtn = document.getElementById('migrate-host-btn');
  if (migrateBtn) migrateBtn.addEventListener('click', migrateHostFromUrl);

  var exportDlBtn = document.getElementById('export-manifest-download-btn');
  if (exportDlBtn) exportDlBtn.addEventListener('click', downloadManifestJSON);
  var exportCpBtn = document.getElementById('export-manifest-copy-btn');
  if (exportCpBtn) exportCpBtn.addEventListener('click', copyManifestToClipboard);
}

function generateManifestJSON() {
  var docs = getLocalDocs();
  var items = docs.map(function(d) {
    return {
      titre: d.title ? (d.title.ar || d.title.fr || d.title.en || '') : '',
      titreAr: d.title ? d.title.ar || '' : '',
      titreFr: d.title ? d.title.fr || '' : '',
      titreEn: d.title ? d.title.en || '' : '',
      niveau: d.level || '',
      filiere: d.stream || '',
      matiere: d.subject || '',
      type_doc_label: d.type || '',
      annee: d.year || '',
      trimestre: d.trimestre || '',
      wilaya: d.wilaya || '',
      tailleFichier: d.size || '',
      pages: d.pages || '',
      urlCloud: d.previewUrl || '',
      urlPartage: d.downloadUrl || '',
      provider: d.host || '',
      source: d.source || '',
      urlSource: d.urlSource || '',
      urlPdf: d.urlPdf || ''
    };
  });
  return { items: items, generatedAt: new Date().toISOString(), count: items.length, source: 'inry-biblio-blogger' };
}

function downloadManifestJSON() {
  var manifest = generateManifestJSON();
  if (!manifest.items.length) { showToast('Aucun document à exporter.'); return; }
  var blob = new Blob([JSON.stringify(manifest, null, 2)], { type: 'application/json' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url;
  a.download = 'manifest-inry-biblio-' + Date.now() + '.json';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  var stats = document.getElementById('export-manifest-stats');
  if (stats) stats.textContent = manifest.items.length + ' document(s) exporté(s) — ' + manifest.generatedAt;
  showToast(manifest.items.length + ' document(s) téléchargé(s)');
}

function copyManifestToClipboard() {
  var manifest = generateManifestJSON();
  if (!manifest.items.length) { showToast('Aucun document à exporter.'); return; }
  var text = JSON.stringify(manifest, null, 2);
  navigator.clipboard.writeText(text).then(function() {
    var stats = document.getElementById('export-manifest-stats');
    if (stats) stats.textContent = manifest.items.length + ' document(s) copiés — ' + manifest.generatedAt;
    showToast(manifest.items.length + ' document(s) copiés dans le presse-papier');
  }).catch(function() {
    showToast('Erreur: impossible de copier');
  });
}

function getFieldValue(item, aliases) {
  for (var i = 0; i < aliases.length; i++) {
    var alias = aliases[i];
    var val;
    if (alias.indexOf('.') !== -1) {
      val = alias.split('.').reduce(function(o, k) { return (o != null ? o[k] : undefined); }, item);
    } else {
      val = item[alias];
    }
    if (val != null && val !== '') return val;
  }
  return '';
}

var IMPORT_ALIASES = {
  'title.ar': ['titre', 'title.ar', 'title', 'العنوان'],
  'title.fr': ['title.fr', 'titreFr', 'titre_fr'],
  'title.en': ['title.en', 'titreEn', 'titre_en'],
  level: ['niveau', 'level', 'grade', 'المستوى', 'classe'],
  stream: ['filiere', 'stream', 'branch', 'الشعبة'],
  subject: ['matiere', 'subject', 'subjectName', 'المادة'],
  type: ['type_doc_label', 'type', 'type_doc', 'docType', 'النوع'],
  year: ['annee', 'year', 'année', 'السنة'],
  trimestre: ['trimestre', 'trimester', 'term', 'الفصل'],
  wilaya: ['wilaya', 'codeWilaya', 'ولاية'],
  size: ['tailleFichier', 'taille_octets', 'tailleOctets', 'size', 'fileSize', 'filesize', 'الحجم'],
  pages: ['pages', 'nbrPages', 'pageCount', 'عدد الصفحات'],
  previewUrl: ['urlCloud', 'url_cloud', 'previewUrl', 'cloudUrl', 'preview'],
  downloadUrl: ['urlPartage', 'url_partage', 'downloadUrl', 'shareUrl', 'downloadLink'],
  host: ['provider', 'site', 'host', 'website', 'platform'],
  source: ['source', 'siteSource', 'origin'],
  urlSource: ['urlSource', 'url_source', 'sourceUrl'],
  urlPdf: ['urlPdf', 'url_pdf', 'pdfUrl'],
  hasSolution: ['hasSolution', 'corrige', 'solution', 'avecCorrection', 'مع التصحيح']
};

function normalizeImportItem(item) {
  var size = getFieldValue(item, IMPORT_ALIASES.size);
  var sizeNum = parseInt(size, 10);
  var sizeStr = !isNaN(sizeNum) && sizeNum > 0
    ? (sizeNum >= 1048576 ? (sizeNum / 1048576).toFixed(1) + ' MB' : Math.round(sizeNum / 1024) + ' KB')
    : String(size || '');
  var hasSolution = getFieldValue(item, IMPORT_ALIASES.hasSolution);
  return {
    title: {
      ar: getFieldValue(item, IMPORT_ALIASES['title.ar']),
      fr: getFieldValue(item, IMPORT_ALIASES['title.fr']),
      en: getFieldValue(item, IMPORT_ALIASES['title.en'])
    },
    level: getFieldValue(item, IMPORT_ALIASES.level),
    stream: getFieldValue(item, IMPORT_ALIASES.stream) || null,
    subject: getFieldValue(item, IMPORT_ALIASES.subject),
    type: getFieldValue(item, IMPORT_ALIASES.type),
    year: getFieldValue(item, IMPORT_ALIASES.year),
    trimestre: getFieldValue(item, IMPORT_ALIASES.trimestre) || null,
    wilaya: getFieldValue(item, IMPORT_ALIASES.wilaya) || '',
    size: sizeStr,
    pages: getFieldValue(item, IMPORT_ALIASES.pages) || '',
    previewUrl: getFieldValue(item, IMPORT_ALIASES.previewUrl),
    downloadUrl: getFieldValue(item, IMPORT_ALIASES.downloadUrl),
    host: getFieldValue(item, IMPORT_ALIASES.host) || 'dzexams',
    source: getFieldValue(item, IMPORT_ALIASES.source) || '',
    urlSource: getFieldValue(item, IMPORT_ALIASES.urlSource) || '',
    urlPdf: getFieldValue(item, IMPORT_ALIASES.urlPdf) || '',
    tags: hasSolution ? ['solution'] : []
  };
}

function renderImportPreview(parsedDocs, rawDocs) {
  var container = document.getElementById('import-preview-container');
  if (!container || !parsedDocs.length) return;
  var html = '<div style="display:flex;align-items:center;gap:var(--space-2);margin-bottom:var(--space-2);flex-wrap:wrap;">';
  html += '<h4 style="margin:0;">' + parsedDocs.length + ' document(s) trouvé(s)</h4>';
  html += '<button class="btn btn-primary" id="import-add-all-btn">➕ Tout ajouter en une fois</button>';
  html += '</div>';
  html += '<div style="max-height:400px;overflow-y:auto;border:1px solid var(--kraft-line);border-radius:var(--radius-sm);">';
  html += '<table class="admin-doc-table"><thead><tr>' +
    '<th>Titre (AR)</th><th>Niveau</th><th>Matière</th><th>Type</th><th>Taille</th><th>Action</th>' +
    '</tr></thead><tbody>';
  parsedDocs.forEach(function(doc, i) {
    html += '<tr>' +
      '<td style="max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" dir="rtl">' + escapeHTML(doc.title.ar.slice(0,60)) + '</td>' +
      '<td>' + escapeHTML(doc.level) + '</td>' +
      '<td>' + escapeHTML(doc.subject) + '</td>' +
      '<td>' + escapeHTML(doc.type) + '</td>' +
      '<td>' + escapeHTML(doc.size) + '</td>' +
      '<td><button class="btn btn-primary btn-sm prefill-from-import-btn" data-index="' + i + '">Pré-remplir</button></td>' +
      '</tr>';
  });
  html += '</tbody></table></div>';
  html += '<p class="export-hint" style="margin-top:var(--space-2);">Cliquez sur "Pré-remplir" pour un document, ou "Tout ajouter en une fois" pour tous les importer directement.</p>';
  container.innerHTML = html;
  container.style.display = 'block';
  container.querySelectorAll('.prefill-from-import-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      var idx = parseInt(btn.dataset.index, 10);
      prefillFormFromImport(parsedDocs[idx], rawDocs[idx]);
    });
  });
  var addAllBtn = document.getElementById('import-add-all-btn');
  if (addAllBtn) {
    addAllBtn.addEventListener('click', function() { batchAddAll(parsedDocs, rawDocs); });
  }
}

async function prefillFormFromImport(doc, raw) {
  var setVal = function(id, val) { var el = document.getElementById(id); if (el) el.value = val; };
  var frTitle = doc.title.fr || await translateFromAr(doc.title.ar, 'fr');
  var enTitle = doc.title.en || await translateFromAr(doc.title.ar, 'en');
  setVal('doc-form-title-fr', frTitle);
  setVal('doc-form-title-ar', doc.title.ar);
  setVal('doc-form-title-en', enTitle);
  setVal('doc-form-desc-fr', frTitle);
  setVal('doc-form-desc-ar', doc.title.ar);
  setVal('doc-form-desc-en', enTitle);
  setVal('doc-form-level', doc.level);
  setVal('doc-form-stream', doc.stream || '');
  setVal('doc-form-subject', doc.subject);
  setVal('doc-form-type', doc.type);
  setVal('doc-form-year', doc.year);
  setVal('doc-form-trimestre', doc.trimestre || '');
  setVal('doc-form-wilaya', doc.wilaya || '');
  setVal('doc-form-pages', doc.pages);
  setVal('doc-form-size', doc.size);
  setVal('doc-form-host', doc.host);
  setVal('doc-form-source', doc.source || '');
  setVal('doc-form-url-source', doc.urlSource || '');
  setVal('doc-form-url-pdf', doc.urlPdf || '');
  setVal('doc-form-preview-url', doc.previewUrl);
  setVal('doc-form-download-url', doc.downloadUrl);
  document.querySelectorAll('.admin-sub-tab').forEach(function(b) { b.classList.remove('active'); });
  var addTab = document.querySelector('.admin-sub-tab[data-subtab="docs-add"]');
  if (addTab) addTab.classList.add('active');
  document.querySelectorAll('#tab-panel-docs .admin-sub-panel').forEach(function(p) { p.classList.add('hidden'); });
  var addPanel = document.getElementById('sub-panel-docs-add');
  if (addPanel) addPanel.classList.remove('hidden');
}

async function fpBoot() {
  try {
    await loadDataWithHidden();
    applyLocalDocOverrides();
    applyLangToDocument();
    document.getElementById('modal-root').innerHTML = renderDocModal();
    window.addEventListener('hashchange', fpRoute);
    fpRoute();
  } catch (e) {
    console.error('[fpBoot]', e);
    var d = document.createElement('div');
    d.style.cssText = 'position:fixed;top:0;left:0;right:0;background:#9c3b2e;color:#fff;padding:8px;z-index:9999;font-size:14px;';
    d.textContent = 'Erreur de démarrage INRY-Biblio : ' + e.message;
    document.body.prepend(d);
  }
}

/* Hook global attendu par js/i18n.js après un changement de langue */
function onLangChange() { fpRoute(); }

fpBoot();

